const networkForensicsHtml = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>NETFOR//07 — Network Forensics</title>\n<style>\n@import url('https://fonts.googleapis.com/css2?family=Azeret+Mono:wght@300;400;600;700&family=Russo+One&family=Barlow+Condensed:wght@300;400;600;700&display=swap');\n\n:root {\n  --abyss:   #020810;\n  --deep1:   #050e1f;\n  --deep2:   #081428;\n  --deep3:   #0c1d38;\n  --deep4:   #102448;\n\n  --sonar:   #00c8ff;\n  --sonar2:  #0098cc;\n  --sonar3:  #006699;\n  --sonar4:  #003d5c;\n  --ping:    #00ffcc;\n  --ping2:   #00cc99;\n  --warn:    #ff8c1a;\n  --warn2:   #cc5500;\n  --red:     #ff2244;\n  --red2:    #cc0022;\n  --silver:  #b0cce0;\n  --dim:     #2a4a6a;\n  --muted:   #0f2035;\n  --rule:    #0a1a2a;\n\n  --mono: 'Azeret Mono', monospace;\n  --display: 'Russo One', sans-serif;\n  --body: 'Barlow Condensed', sans-serif;\n}\n\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\nhtml{scroll-behavior:smooth}\n\nbody {\n  background: var(--abyss);\n  color: var(--silver);\n  font-family: var(--body);\n  min-height: 100vh;\n  overflow-x: hidden;\n}\n\n/* ── DEPTH CONTOURS ── */\nbody::before {\n  content: '';\n  position: fixed; inset: 0;\n  background-image:\n    repeating-radial-gradient(ellipse 120% 80% at 50% -20%,\n      transparent 0px, transparent 120px,\n      rgba(0,200,255,.025) 120px, rgba(0,200,255,.025) 121px,\n      transparent 121px, transparent 260px,\n      rgba(0,200,255,.018) 260px, rgba(0,200,255,.018) 261px,\n      transparent 261px, transparent 420px,\n      rgba(0,200,255,.012) 420px, rgba(0,200,255,.012) 421px\n    );\n  pointer-events: none; z-index: 0;\n}\n\n/* Sonar ping animation */\n@keyframes sonar-ring {\n  0%   { transform: translate(-50%,-50%) scale(0); opacity: .6; }\n  100% { transform: translate(-50%,-50%) scale(4); opacity: 0; }\n}\n\n.sonar-origin {\n  position: fixed;\n  top: 30%; left: 75%;\n  width: 2px; height: 2px;\n  pointer-events: none; z-index: 0;\n}\n.sonar-ring {\n  position: absolute; top: 50%; left: 50%;\n  width: 200px; height: 200px;\n  border: 1px solid rgba(0,200,255,.3);\n  border-radius: 50%;\n  animation: sonar-ring 6s ease-out infinite;\n}\n.sonar-ring:nth-child(2) { animation-delay: 2s; }\n.sonar-ring:nth-child(3) { animation-delay: 4s; }\n\n.z1 { position: relative; z-index: 1; }\n\n/* ── NAV ── */\nnav {\n  position: sticky; top: 0; z-index: 200;\n  display: flex; align-items: stretch;\n  background: rgba(2,8,16,.96);\n  backdrop-filter: blur(20px);\n  border-bottom: 1px solid rgba(0,200,255,.15);\n  overflow-x: auto; scrollbar-width: none;\n  box-shadow: 0 4px 30px rgba(0,0,0,.5);\n}\nnav::-webkit-scrollbar { display: none; }\n\n.nav-brand {\n  display: flex; align-items: center; gap: 14px;\n  padding: 0 24px;\n  border-right: 1px solid var(--rule);\n  flex-shrink: 0;\n}\n.nav-sonar-dot {\n  width: 10px; height: 10px;\n  background: var(--sonar);\n  border-radius: 50%;\n  box-shadow: 0 0 0 0 rgba(0,200,255,.6);\n  animation: sonar-pulse 2.5s ease-out infinite;\n}\n@keyframes sonar-pulse {\n  0%   { box-shadow: 0 0 0 0 rgba(0,200,255,.6); }\n  70%  { box-shadow: 0 0 0 10px rgba(0,200,255,0); }\n  100% { box-shadow: 0 0 0 0 rgba(0,200,255,0); }\n}\n.nav-title {\n  font-family: var(--display);\n  font-size: .85rem;\n  letter-spacing: 3px;\n  color: var(--sonar);\n  white-space: nowrap;\n}\n\n.ntabs { display: flex; }\n.ntab {\n  font-family: var(--mono);\n  font-size: .55rem;\n  font-weight: 600;\n  letter-spacing: 1.5px;\n  text-transform: uppercase;\n  padding: 0 16px;\n  cursor: pointer;\n  color: var(--dim);\n  background: none; border: none;\n  border-right: 1px solid var(--rule);\n  white-space: nowrap;\n  transition: all .2s;\n}\n.ntab:hover { color: var(--sonar); background: rgba(0,200,255,.04); }\n.ntab.active { color: var(--abyss); background: var(--sonar2); font-weight: 700; }\n\n/* ── HERO ── */\n.hero {\n  display: grid;\n  grid-template-columns: 1fr 300px;\n  min-height: 220px;\n  border-bottom: 1px solid rgba(0,200,255,.1);\n}\n@media(max-width:760px){ .hero{grid-template-columns:1fr} }\n\n.hero-main {\n  padding: 52px 52px 44px;\n  border-right: 1px solid rgba(0,200,255,.08);\n  position: relative;\n  overflow: hidden;\n}\n\n/* Grid overlay on hero */\n.hero-main::before {\n  content: '';\n  position: absolute; inset: 0;\n  background-image:\n    linear-gradient(rgba(0,200,255,.04) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(0,200,255,.04) 1px, transparent 1px);\n  background-size: 32px 32px;\n  pointer-events: none;\n}\n\n.hero-eyebrow {\n  font-family: var(--mono);\n  font-size: .55rem;\n  letter-spacing: 5px;\n  color: var(--sonar3);\n  margin-bottom: 16px;\n  text-transform: uppercase;\n  display: flex; align-items: center; gap: 10px;\n}\n.hero-eyebrow::before {\n  content: '';\n  display: inline-block;\n  width: 30px; height: 1px;\n  background: var(--sonar3);\n}\n\n.hero-h1 {\n  font-family: var(--display);\n  font-size: clamp(3rem, 7vw, 5.5rem);\n  line-height: .9;\n  letter-spacing: 1px;\n  color: var(--silver);\n  margin-bottom: 20px;\n  position: relative;\n}\n.hero-h1 .hl {\n  color: var(--sonar);\n  text-shadow: 0 0 30px rgba(0,200,255,.4);\n}\n\n.hero-desc {\n  font-family: var(--body);\n  font-size: 1rem;\n  font-weight: 300;\n  color: var(--dim);\n  line-height: 1.7;\n  max-width: 500px;\n  margin-bottom: 24px;\n  letter-spacing: .3px;\n}\n\n.hero-chips { display: flex; flex-wrap: wrap; gap: 6px; }\n.hchip {\n  font-family: var(--mono);\n  font-size: .52rem;\n  letter-spacing: 1.5px;\n  padding: 4px 10px;\n  border: 1px solid var(--sonar4);\n  color: var(--sonar3);\n  text-transform: uppercase;\n}\n\n.hero-panel {\n  background: var(--deep1);\n  display: flex; flex-direction: column;\n}\n.hp-row {\n  flex: 1;\n  padding: 16px 22px;\n  border-bottom: 1px solid var(--rule);\n  display: flex; flex-direction: column; justify-content: center;\n}\n.hp-row:last-child { border-bottom: none; }\n.hp-label {\n  font-family: var(--mono);\n  font-size: .48rem;\n  letter-spacing: 3px;\n  color: var(--dim);\n  text-transform: uppercase;\n  margin-bottom: 5px;\n}\n.hp-val {\n  font-family: var(--display);\n  font-size: 1.3rem;\n  letter-spacing: 1px;\n  color: var(--ping);\n  text-shadow: 0 0 15px rgba(0,255,204,.3);\n}\n.hp-sub {\n  font-family: var(--mono);\n  font-size: .58rem;\n  color: var(--sonar3);\n  margin-top: 2px;\n}\n\n/* ── MODULE / WRAPPER ── */\n.module{display:none}\n.module.active{display:block}\n.wrapper{max-width:1200px;margin:0 auto;padding:44px 52px 80px}\n@media(max-width:640px){.wrapper{padding:24px 16px 60px}}\n\n/* ── SECTION HEADER ── */\n.sh {\n  display: grid;\n  grid-template-columns: 56px 1fr;\n  gap: 20px;\n  margin-bottom: 32px;\n  padding-bottom: 18px;\n  border-bottom: 1px solid rgba(0,200,255,.08);\n}\n.sh-num {\n  font-family: var(--display);\n  font-size: 2.8rem;\n  color: var(--muted);\n  line-height: 1;\n  padding-top: 4px;\n  text-align: right;\n}\n.sh-eyebrow {\n  font-family: var(--mono);\n  font-size: .5rem;\n  letter-spacing: 4px;\n  color: var(--dim);\n  text-transform: uppercase;\n  margin-bottom: 6px;\n}\n.sh-title {\n  font-family: var(--display);\n  font-size: 1.7rem;\n  letter-spacing: .5px;\n  color: var(--silver);\n  margin-bottom: 6px;\n  line-height: 1;\n}\n.sh-title .hl { color: var(--sonar); }\n.sh-desc {\n  font-family: var(--body);\n  font-size: .92rem;\n  color: var(--dim);\n  font-weight: 300;\n  line-height: 1.65;\n  max-width: 700px;\n}\n\n/* ── GRIDS ── */\n.g2{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}\n.g3{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}\n.gasym{display:grid;grid-template-columns:1.5fr 1fr;gap:12px}\n@media(max-width:860px){.g2,.g3,.gasym{grid-template-columns:1fr}}\n\n/* ── CARDS ── */\n.card {\n  background: var(--deep1);\n  border: 1px solid rgba(0,200,255,.08);\n  padding: 20px;\n  position: relative;\n  overflow: hidden;\n  transition: border-color .25s, box-shadow .25s;\n}\n.card:hover {\n  border-color: rgba(0,200,255,.2);\n  box-shadow: 0 0 20px rgba(0,200,255,.06);\n}\n.card::after {\n  content: '';\n  position: absolute;\n  top: 0; left: 0; right: 0;\n  height: 1px;\n  background: var(--card-top, transparent);\n  transition: background .3s;\n}\n.card:hover::after { background: var(--card-hover, transparent); }\n\n.cs  { --card-hover: rgba(0,200,255,.5); }\n.cp  { --card-hover: rgba(0,255,204,.4); }\n.cw  { --card-hover: rgba(255,140,26,.4); }\n.cr  { --card-hover: rgba(255,34,68,.4); }\n\n.clabel {\n  font-family: var(--mono);\n  font-size: .5rem;\n  letter-spacing: 3px;\n  color: var(--dim);\n  text-transform: uppercase;\n  margin-bottom: 7px;\n}\n.ctitle {\n  font-family: var(--display);\n  font-size: .95rem;\n  letter-spacing: .5px;\n  color: var(--silver);\n  margin-bottom: 10px;\n  line-height: 1.1;\n}\n.ctitle.sonar { color: var(--sonar); }\n.ctitle.ping  { color: var(--ping); }\n.ctitle.warn  { color: var(--warn); }\n.ctitle.red   { color: var(--red); }\n\n.cbody {\n  font-family: var(--body);\n  font-size: .88rem;\n  color: var(--dim);\n  line-height: 1.7;\n  font-weight: 300;\n}\n.cbody strong { color: var(--silver); font-weight: 600; }\n.cbody code {\n  font-family: var(--mono);\n  font-size: .75rem;\n  color: var(--ping);\n  background: rgba(0,255,204,.06);\n  padding: 1px 5px;\n  border: 1px solid rgba(0,255,204,.12);\n}\n\n/* ── CODE BLOCKS ── */\n.cb {\n  background: #010508;\n  border: 1px solid rgba(0,200,255,.07);\n  border-left: 2px solid var(--cb-accent, rgba(0,200,255,.3));\n  padding: 14px 16px;\n  font-family: var(--mono);\n  font-size: .67rem;\n  font-weight: 400;\n  line-height: 1.95;\n  overflow-x: auto;\n  margin: 10px 0;\n  color: #1a3a5a;\n  position: relative;\n}\n.cb .tag {\n  position: absolute; top: 5px; right: 8px;\n  font-size: .48rem; letter-spacing: 2px;\n  color: rgba(0,200,255,.25); text-transform: uppercase;\n}\n.K  { color: #00c8ff; font-weight: 700; }\n.F  { color: #00ffcc; }\n.S  { color: #88ddff; }\n.N  { color: #ff8c1a; }\n.C  { color: #0f2840; font-style: italic; }\n.V  { color: #66aadd; }\n.H  { color: #aaccdd; }\n.R  { color: #ff2244; }\n.G  { color: #00ffcc; }\n.Y  { color: #ff8c1a; }\n.W  { color: #b0cce0; }\n.P  { color: #cc88ff; }\n.DIM{ color: #0f2840; }\n\n/* ── ALERT ── */\n.alert {\n  border: 1px solid;\n  padding: 10px 14px;\n  margin: 10px 0;\n  font-family: var(--body);\n  font-size: .88rem;\n  line-height: 1.6;\n  font-weight: 300;\n}\n.alert strong { font-weight: 700; }\n.a-warn { border-color: rgba(255,140,26,.4); color: var(--warn); background: rgba(255,140,26,.04); }\n.a-info { border-color: rgba(0,200,255,.3); color: var(--sonar2); background: rgba(0,200,255,.04); }\n.a-ok   { border-color: rgba(0,255,204,.3); color: var(--ping2); background: rgba(0,255,204,.04); }\n.a-err  { border-color: rgba(255,34,68,.35); color: var(--red); background: rgba(255,34,68,.04); }\n\n/* ── TABLE ── */\n.dtable { width: 100%; border-collapse: collapse; margin: 10px 0; }\n.dtable th {\n  font-family: var(--mono);\n  font-size: .52rem;\n  letter-spacing: 2px;\n  text-transform: uppercase;\n  padding: 8px 12px;\n  text-align: left;\n  background: var(--deep3);\n  color: var(--sonar);\n  border: 1px solid rgba(0,200,255,.1);\n}\n.dtable td {\n  font-family: var(--body);\n  font-size: .85rem;\n  font-weight: 300;\n  padding: 8px 12px;\n  border: 1px solid var(--rule);\n  vertical-align: top;\n  line-height: 1.5;\n  color: var(--dim);\n}\n.dtable tr:nth-child(even) td { background: rgba(0,200,255,.02); }\n.dtable tr:hover td { background: rgba(0,200,255,.05); color: var(--silver); }\n.dtable td strong { color: var(--silver); font-weight: 600; }\n.dtable td code { font-family: var(--mono); font-size: .72rem; color: var(--ping); }\n.tc-r { color: var(--red)!important; font-family: var(--mono); font-size: .72rem; font-weight: 700; }\n.tc-y { color: var(--warn)!important; font-family: var(--mono); font-size: .72rem; font-weight: 700; }\n.tc-g { color: var(--ping2)!important; font-family: var(--mono); font-size: .72rem; font-weight: 700; }\n.tc-s { color: var(--sonar2)!important; font-family: var(--mono); font-size: .72rem; font-weight: 700; }\n\n/* ── DIVIDER ── */\n.divline { height: 1px; background: linear-gradient(90deg,transparent,rgba(0,200,255,.15),transparent); margin: 24px 0; }\n\n/* ── BADGES ── */\n.badges { display: flex; flex-wrap: wrap; gap: 5px; margin-top: 10px; }\n.badge {\n  font-family: var(--mono);\n  font-size: .5rem;\n  letter-spacing: 1.5px;\n  padding: 2px 8px;\n  border: 1px solid;\n  text-transform: uppercase;\n}\n.bs { color: var(--sonar2); border-color: rgba(0,200,255,.35); background: rgba(0,200,255,.05); }\n.bp { color: var(--ping2); border-color: rgba(0,255,204,.3); background: rgba(0,255,204,.05); }\n.bw { color: var(--warn); border-color: rgba(255,140,26,.3); background: rgba(255,140,26,.05); }\n.br { color: var(--red); border-color: rgba(255,34,68,.3); background: rgba(255,34,68,.05); }\n\n/* ── IN-PAGE TABS ── */\n.itabs {\n  display: flex; border-bottom: 1px solid rgba(0,200,255,.08);\n  margin-bottom: 0; overflow-x: auto; scrollbar-width: none;\n}\n.itabs::-webkit-scrollbar { display: none; }\n.itab {\n  font-family: var(--mono);\n  font-size: .54rem;\n  letter-spacing: 2px;\n  text-transform: uppercase;\n  padding: 9px 14px;\n  cursor: pointer;\n  color: var(--dim);\n  background: none; border: none;\n  border-bottom: 2px solid transparent;\n  margin-bottom: -1px;\n  white-space: nowrap;\n  transition: all .18s;\n}\n.itab:hover { color: var(--sonar); }\n.itab.active { color: var(--sonar); border-bottom-color: var(--sonar); }\n.ipanel { display: none; padding-top: 20px; }\n.ipanel.active { display: block; }\n\n/* ── PACKET ANATOMY DISPLAY ── */\n.packet-layers {\n  display: flex; flex-direction: column; gap: 2px;\n  margin: 14px 0;\n}\n.pkt-layer {\n  display: flex; align-items: center; gap: 12px;\n  padding: 10px 16px;\n  border: 1px solid;\n  transition: all .2s;\n  cursor: default;\n}\n.pkt-layer:hover { transform: translateX(4px); }\n.pl-1 { border-color: rgba(255,34,68,.3); background: rgba(255,34,68,.04); }\n.pl-2 { border-color: rgba(255,140,26,.3); background: rgba(255,140,26,.04); margin: 0 8px; }\n.pl-3 { border-color: rgba(0,200,255,.2); background: rgba(0,200,255,.04); margin: 0 16px; }\n.pl-4 { border-color: rgba(0,255,204,.2); background: rgba(0,255,204,.04); margin: 0 24px; }\n.pl-5 { border-color: rgba(176,204,224,.15); background: rgba(176,204,224,.04); margin: 0 32px; }\n.pkt-num {\n  font-family: var(--mono);\n  font-size: .55rem;\n  letter-spacing: 2px;\n  min-width: 50px;\n}\n.pl-1 .pkt-num { color: var(--red); }\n.pl-2 .pkt-num { color: var(--warn); }\n.pl-3 .pkt-num { color: var(--sonar2); }\n.pl-4 .pkt-num { color: var(--ping2); }\n.pl-5 .pkt-num { color: var(--dim); }\n.pkt-name {\n  font-family: var(--display);\n  font-size: .85rem;\n  letter-spacing: 1px;\n  min-width: 100px;\n}\n.pkt-fields {\n  font-family: var(--mono);\n  font-size: .62rem;\n  color: var(--dim);\n  flex: 1;\n}\n.pkt-forensic {\n  font-family: var(--mono);\n  font-size: .58rem;\n  text-align: right;\n  flex-shrink: 0;\n}\n.pl-1 .pkt-forensic { color: var(--red); }\n.pl-2 .pkt-forensic { color: var(--warn); }\n.pl-3 .pkt-forensic { color: var(--sonar3); }\n.pl-4 .pkt-forensic { color: var(--ping2); }\n\n/* ── WIRESHARK FILTER BAR ── */\n.filter-bar {\n  background: #010508;\n  border: 1px solid rgba(0,200,255,.1);\n  border-radius: 0;\n  padding: 0;\n  overflow: hidden;\n  margin: 10px 0;\n}\n.fb-label {\n  background: rgba(0,200,255,.06);\n  border-bottom: 1px solid rgba(0,200,255,.1);\n  padding: 5px 12px;\n  font-family: var(--mono);\n  font-size: .52rem;\n  letter-spacing: 2px;\n  color: var(--sonar3);\n  text-transform: uppercase;\n}\n.fb-filter {\n  display: flex; align-items: center; gap: 10px;\n  padding: 7px 12px;\n  border-bottom: 1px solid rgba(0,200,255,.05);\n  font-family: var(--mono);\n  font-size: .68rem;\n  color: var(--sonar);\n  transition: background .15s;\n}\n.fb-filter:last-child { border-bottom: none; }\n.fb-filter:hover { background: rgba(0,200,255,.03); }\n.fb-desc { font-family: var(--body); font-size: .78rem; color: var(--dim); flex: 1; font-weight: 300; margin-left: 8px; }\n\n/* ── QUIZ ── */\n.qcard {\n  background: var(--deep1);\n  border: 1px solid rgba(0,200,255,.08);\n  padding: 20px;\n  margin-bottom: 10px;\n  transition: border-color .2s;\n}\n.qcard:hover { border-color: rgba(0,200,255,.15); }\n.qnum {\n  font-family: var(--mono);\n  font-size: .5rem;\n  letter-spacing: 3px;\n  color: var(--dim);\n  text-transform: uppercase;\n  margin-bottom: 8px;\n}\n.qtext {\n  font-family: var(--body);\n  font-size: 1rem;\n  font-weight: 600;\n  color: var(--silver);\n  margin-bottom: 14px;\n  line-height: 1.5;\n  letter-spacing: .2px;\n}\n.qopts { display: flex; flex-direction: column; gap: 5px; }\n.qopt {\n  font-family: var(--mono);\n  font-size: .67rem;\n  padding: 9px 12px;\n  border: 1px solid var(--rule);\n  background: var(--abyss);\n  color: var(--dim);\n  text-align: left;\n  cursor: pointer;\n  transition: all .15s;\n  line-height: 1.45;\n}\n.qopt:hover:not(.locked) { border-color: rgba(0,200,255,.3); color: var(--sonar); }\n.qopt.correct { border-color: rgba(0,255,204,.5); background: rgba(0,255,204,.07); color: var(--ping); }\n.qopt.wrong   { border-color: rgba(255,34,68,.4); background: rgba(255,34,68,.05); color: var(--red); }\n.qexplain {\n  margin-top: 10px;\n  padding: 10px 14px;\n  background: var(--deep1);\n  border-left: 2px solid var(--sonar3);\n  font-family: var(--body);\n  font-size: .85rem;\n  color: var(--dim);\n  line-height: 1.7;\n  display: none;\n  font-weight: 300;\n}\n.qexplain.show { display: block; }\n.qexplain strong { color: var(--sonar); font-weight: 700; }\n.qexplain code { font-family: var(--mono); font-size: .73rem; color: var(--ping); }\n\n.score-panel {\n  background: var(--deep1);\n  border: 1px solid rgba(0,200,255,.2);\n  padding: 28px;\n  text-align: center;\n  margin-top: 16px;\n  position: relative;\n  overflow: hidden;\n}\n.score-panel::before {\n  content: '';\n  position: absolute; inset: 0;\n  background: radial-gradient(ellipse 60% 60% at 50% 50%, rgba(0,200,255,.04) 0%, transparent 70%);\n  pointer-events: none;\n}\n.score-big {\n  font-family: var(--display);\n  font-size: 3.5rem;\n  color: var(--sonar);\n  line-height: 1;\n  margin-bottom: 6px;\n  text-shadow: 0 0 30px rgba(0,200,255,.4);\n}\n.score-sub {\n  font-family: var(--mono);\n  font-size: .55rem;\n  letter-spacing: 3px;\n  color: var(--dim);\n  text-transform: uppercase;\n  margin-bottom: 16px;\n}\n.score-bar { height: 2px; background: var(--muted); max-width: 280px; margin: 0 auto 16px; }\n.score-fill { height: 100%; transition: width .6s; }\n.reset-btn {\n  font-family: var(--mono);\n  font-size: .57rem;\n  letter-spacing: 2px;\n  text-transform: uppercase;\n  padding: 8px 20px;\n  background: none;\n  color: var(--sonar2);\n  border: 1px solid rgba(0,200,255,.3);\n  cursor: pointer;\n  transition: all .2s;\n}\n.reset-btn:hover { background: rgba(0,200,255,.08); color: var(--sonar); }\n</style>\n</head>\n<body>\n\n<div class=\"sonar-origin\">\n  <div class=\"sonar-ring\"></div>\n  <div class=\"sonar-ring\"></div>\n  <div class=\"sonar-ring\"></div>\n</div>\n\n<!-- NAV -->\n<nav class=\"z1\">\n  <div class=\"nav-brand\">\n    <div class=\"nav-sonar-dot\"></div>\n    <div class=\"nav-title\">NETFOR // 07</div>\n  </div>\n  <div class=\"ntabs\">\n    <button class=\"ntab active\" onclick=\"sw('overview',this)\">Overview</button>\n    <button class=\"ntab\" onclick=\"sw('pcap',this)\">PCAP Analysis</button>\n    <button class=\"ntab\" onclick=\"sw('zeek',this)\">Zeek</button>\n    <button class=\"ntab\" onclick=\"sw('suricata',this)\">Suricata</button>\n    <button class=\"ntab\" onclick=\"sw('dns',this)\">DNS Forensics</button>\n    <button class=\"ntab\" onclick=\"sw('tls',this)\">TLS / JA3</button>\n    <button class=\"ntab\" onclick=\"sw('c2',this)\">C2 Detection</button>\n    <button class=\"ntab\" onclick=\"sw('lateral',this)\">Lateral Movement</button>\n    <button class=\"ntab\" onclick=\"sw('quiz',this)\">Exam</button>\n  </div>\n</nav>\n\n<!-- HERO -->\n<div class=\"hero z1\">\n  <div class=\"hero-main\">\n    <div class=\"hero-eyebrow\">Module 07 — Network Forensics & Traffic Analysis</div>\n    <h1 class=\"hero-h1\">SEE EVERY<br><span class=\"hl\">PACKET.</span><br>HEAR EVERY<br><span class=\"hl\">SIGNAL.</span></h1>\n    <p class=\"hero-desc\">PCAP dissection, Zeek log correlation, Suricata rule authoring, DNS anomaly detection, TLS fingerprinting with JA3, C2 beacon analysis, and lateral movement detection from raw network evidence.</p>\n    <div class=\"hero-chips\">\n      <span class=\"hchip\">Wireshark</span><span class=\"hchip\">Zeek</span><span class=\"hchip\">Suricata</span>\n      <span class=\"hchip\">JA3/JA3S</span><span class=\"hchip\">DNS Forensics</span><span class=\"hchip\">NetFlow</span>\n    </div>\n  </div>\n  <div class=\"hero-panel z1\">\n    <div class=\"hp-row\">\n      <div class=\"hp-label\">Focus Layer</div>\n      <div class=\"hp-val\">NETWORK</div>\n      <div class=\"hp-sub\">OSI Layers 3–7</div>\n    </div>\n    <div class=\"hp-row\">\n      <div class=\"hp-label\">Primary Tools</div>\n      <div class=\"hp-val\">ZEEK</div>\n      <div class=\"hp-sub\">+ Wireshark + Suricata</div>\n    </div>\n    <div class=\"hp-row\">\n      <div class=\"hp-label\">ATT&CK Coverage</div>\n      <div class=\"hp-val\">TA0011</div>\n      <div class=\"hp-sub\">C2 + Exfiltration</div>\n    </div>\n    <div class=\"hp-row\">\n      <div class=\"hp-label\">Key Technique</div>\n      <div class=\"hp-val\">JA3</div>\n      <div class=\"hp-sub\">TLS fingerprinting</div>\n    </div>\n  </div>\n</div>\n\n<!-- ══════════════ OVERVIEW ══════════════ -->\n<div class=\"module active z1\" id=\"mod-overview\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">07</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// The Network Evidence Layer //</div>\n      <div class=\"sh-title\">Why <span class=\"hl\">Network Forensics</span></div>\n      <div class=\"sh-desc\">Every attack traverses the network — even fileless, memory-only malware must communicate. Network evidence is often the only artifact that survives host cleanup, log deletion, or VM reversion. Mastering it closes the gap that host-based forensics leaves open.</div>\n    </div>\n  </div>\n\n  <!-- OSI forensic value by layer -->\n  <div class=\"card cs\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Protocol Stack — Forensic Value</div>\n    <div class=\"ctitle sonar\">PACKET LAYERS & WHAT EACH REVEALS</div>\n    <div class=\"cbody\" style=\"margin-bottom:12px\">Each OSI layer carries distinct forensic signals. A complete network investigation touches all of them.</div>\n    <div class=\"packet-layers\">\n      <div class=\"pkt-layer pl-1\">\n        <span class=\"pkt-num\">L7 APP</span>\n        <span class=\"pkt-name\" style=\"color:var(--red)\">APPLICATION</span>\n        <span class=\"pkt-fields\">HTTP headers · DNS queries · TLS SNI · SMTP envelopes · SMB paths</span>\n        <span class=\"pkt-forensic\">C2 URLs · phishing indicators · exfil data</span>\n      </div>\n      <div class=\"pkt-layer pl-2\">\n        <span class=\"pkt-num\">L6/5</span>\n        <span class=\"pkt-name\" style=\"color:var(--warn)\">TLS/SESSION</span>\n        <span class=\"pkt-fields\">TLS version · cipher suite · SNI · certificate details · JA3 fingerprint</span>\n        <span class=\"pkt-forensic\">Malware TLS profiles · self-signed certs</span>\n      </div>\n      <div class=\"pkt-layer pl-3\">\n        <span class=\"pkt-num\">L4 TRANS</span>\n        <span class=\"pkt-name\" style=\"color:var(--sonar)\">TCP/UDP</span>\n        <span class=\"pkt-fields\">Source/dest ports · TCP flags · sequence numbers · connection state</span>\n        <span class=\"pkt-forensic\">Port scanning · unusual port use · SYN floods</span>\n      </div>\n      <div class=\"pkt-layer pl-4\">\n        <span class=\"pkt-num\">L3 NET</span>\n        <span class=\"pkt-name\" style=\"color:var(--ping2)\">IP</span>\n        <span class=\"pkt-fields\">Source/dest IPs · TTL · protocol · fragmentation · ICMP type</span>\n        <span class=\"pkt-forensic\">C2 IPs · lateral movement paths · tunneling</span>\n      </div>\n      <div class=\"pkt-layer pl-5\">\n        <span class=\"pkt-num\">L2 LINK</span>\n        <span class=\"pkt-name\" style=\"color:var(--dim)\">ETHERNET</span>\n        <span class=\"pkt-fields\">MAC addresses · VLAN tags · ARP</span>\n        <span class=\"pkt-forensic\">ARP poisoning · VLAN hopping</span>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"g3\" style=\"margin-bottom:14px\">\n    <div class=\"card cs\">\n      <div class=\"clabel\">Tool 01</div>\n      <div class=\"ctitle sonar\">Wireshark</div>\n      <div class=\"cbody\">Full packet capture and deep protocol dissection. GUI-based. Best for interactive investigation of specific conversations. Filter language is powerful and expressive.</div>\n      <div class=\"badges\"><span class=\"badge bs\">PCAP</span><span class=\"badge bs\">Interactive</span><span class=\"badge bs\">Protocol Decode</span></div>\n    </div>\n    <div class=\"card cp\">\n      <div class=\"clabel\">Tool 02</div>\n      <div class=\"ctitle ping\">Zeek (Bro)</div>\n      <div class=\"cbody\">Network security monitor. Produces structured logs (conn.log, dns.log, http.log, ssl.log, files.log) ideal for SIEM ingestion and large-scale correlation. Scriptable.</div>\n      <div class=\"badges\"><span class=\"badge bp\">Log Generation</span><span class=\"badge bp\">Scripting</span><span class=\"badge bp\">SIEM Feed</span></div>\n    </div>\n    <div class=\"card cw\">\n      <div class=\"clabel\">Tool 03</div>\n      <div class=\"ctitle warn\">Suricata</div>\n      <div class=\"cbody\">IDS/IPS with Snort-compatible rule format. Real-time alerting against PCAP or live traffic. Rich rule language with protocol keywords, byte matching, and flow tracking.</div>\n      <div class=\"badges\"><span class=\"badge bw\">IDS/IPS</span><span class=\"badge bw\">Real-Time</span><span class=\"badge bw\">Rules</span></div>\n    </div>\n  </div>\n\n  <!-- Network forensics workflow -->\n  <div class=\"card\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Investigation Workflow</div>\n    <div class=\"ctitle\">NETWORK FORENSIC INVESTIGATION PIPELINE</div>\n    <div class=\"cb\">\n<span class=\"C\">################################################################################</span>\n<span class=\"C\"># NETWORK FORENSICS WORKFLOW — Applied to any PCAP or live capture</span>\n<span class=\"C\">################################################################################</span>\n\n<span class=\"Y\">STEP 1: OVERVIEW — What are we looking at?</span>\n<span class=\"K\">capinfos</span> capture.pcap              <span class=\"C\"># duration, packet count, protocols</span>\n<span class=\"K\">tshark</span> -r capture.pcap -q -z io,phs <span class=\"C\"># protocol hierarchy statistics</span>\n<span class=\"K\">tshark</span> -r capture.pcap -q -z conv,tcp <span class=\"C\"># TCP conversation summary</span>\n\n<span class=\"Y\">STEP 2: IDENTIFY HOSTS</span>\n<span class=\"K\">tshark</span> -r capture.pcap -T fields \\\n    -e ip.src -e ip.dst \\\n    -q -z ip_hosts,tree | head -30\n<span class=\"K\">zeek</span> -r capture.pcap             <span class=\"C\"># generate all Zeek logs</span>\n<span class=\"K\">cat</span> conn.log | <span class=\"K\">zeek-cut</span> id.orig_h id.resp_h | <span class=\"K\">sort | uniq -c | sort -rn</span>\n\n<span class=\"Y\">STEP 3: HUNT ANOMALIES</span>\n<span class=\"C\"># DNS: unusual domains, NXDOMAIN storms, long labels</span>\n<span class=\"K\">cat</span> dns.log | <span class=\"K\">zeek-cut</span> query answers | <span class=\"K\">grep</span> -v \".arpa\"\n\n<span class=\"C\"># HTTP: suspicious User-Agents, POST to unusual hosts</span>\n<span class=\"K\">cat</span> http.log | <span class=\"K\">zeek-cut</span> host uri user_agent method | <span class=\"K\">grep</span> POST\n\n<span class=\"C\"># TLS: self-signed certs, unusual JA3, non-standard ports</span>\n<span class=\"K\">cat</span> ssl.log | <span class=\"K\">zeek-cut</span> server_name ja3 ja3s validation_status\n\n<span class=\"Y\">STEP 4: EXTRACT & ANALYZE ARTIFACTS</span>\n<span class=\"C\"># Extract transferred files</span>\n<span class=\"K\">zeek</span> -r capture.pcap /opt/zeek/share/zeek/policy/frameworks/files/extract-all-files.zeek\n<span class=\"K\">file</span> extract_files/*    <span class=\"C\"># identify each extracted file</span>\n<span class=\"K\">sha256sum</span> extract_files/* <span class=\"C\"># hash for VT lookup</span>\n\n<span class=\"Y\">STEP 5: RUN SURICATA RULES</span>\n<span class=\"K\">suricata</span> -r capture.pcap -l ./suricata_output/ \\\n    --runmode single -S emerging-threats.rules</div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════ PCAP ANALYSIS ══════════════ -->\n<div class=\"module z1\" id=\"mod-pcap\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">01</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Packet Capture Analysis //</div>\n      <div class=\"sh-title\">Wireshark & <span class=\"hl\">tshark Mastery</span></div>\n      <div class=\"sh-desc\">Deep packet inspection, display filter syntax, protocol reconstruction, and artifact extraction from PCAP files. tshark for command-line scripting; Wireshark for interactive investigation.</div>\n    </div>\n  </div>\n\n  <!-- Wireshark display filters -->\n  <div class=\"card cs\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Wireshark Display Filter Reference</div>\n    <div class=\"ctitle sonar\">ESSENTIAL FORENSIC FILTERS</div>\n    <div class=\"cbody\" style=\"margin-bottom:10px\">These display filters surface the most forensically relevant traffic. Apply in Wireshark's filter bar or via <code>tshark -Y</code>.</div>\n\n    <div class=\"filter-bar\">\n      <div class=\"fb-label\">// C2 & BEACONING</div>\n      <div class=\"fb-filter\"><span>http.request.method == \"POST\"</span><span class=\"fb-desc\">Data exfiltration or C2 check-in</span></div>\n      <div class=\"fb-filter\"><span>tcp.flags.syn == 1 && tcp.flags.ack == 0</span><span class=\"fb-desc\">All SYN packets — port scan / new connections</span></div>\n      <div class=\"fb-filter\"><span>!(ip.dst == 10.0.0.0/8 || ip.dst == 192.168.0.0/16)</span><span class=\"fb-desc\">All external traffic — exclude RFC1918</span></div>\n      <div class=\"fb-filter\"><span>frame.time_delta &lt; 0.001 && tcp</span><span class=\"fb-desc\">Rapid-fire connections — scanning or DDoS</span></div>\n    </div>\n\n    <div class=\"filter-bar\" style=\"margin-top:8px\">\n      <div class=\"fb-label\">// DNS</div>\n      <div class=\"fb-filter\"><span>dns.flags.rcode == 3</span><span class=\"fb-desc\">NXDOMAIN responses — DGA detection, typosquatting</span></div>\n      <div class=\"fb-filter\"><span>dns.qry.type == 16</span><span class=\"fb-desc\">TXT record queries — DNS tunneling</span></div>\n      <div class=\"fb-filter\"><span>dns.qry.name.len &gt; 50</span><span class=\"fb-desc\">Unusually long hostnames — encoded data in subdomain</span></div>\n      <div class=\"fb-filter\"><span>dns && !dns.flags.response</span><span class=\"fb-desc\">DNS queries only (not responses)</span></div>\n    </div>\n\n    <div class=\"filter-bar\" style=\"margin-top:8px\">\n      <div class=\"fb-label\">// TLS / ENCRYPTED</div>\n      <div class=\"fb-filter\"><span>tls.handshake.type == 1</span><span class=\"fb-desc\">TLS ClientHello — capture JA3 fingerprint here</span></div>\n      <div class=\"fb-filter\"><span>tls.handshake.certificate</span><span class=\"fb-desc\">Certificate exchanges — inspect validity, issuer</span></div>\n      <div class=\"fb-filter\"><span>ssl.alert_message.level == 2</span><span class=\"fb-desc\">TLS fatal alerts — cert rejection, handshake failure</span></div>\n    </div>\n\n    <div class=\"filter-bar\" style=\"margin-top:8px\">\n      <div class=\"fb-label\">// LATERAL MOVEMENT</div>\n      <div class=\"fb-filter\"><span>smb || smb2</span><span class=\"fb-desc\">SMB traffic — file sharing, PsExec, ransomware spread</span></div>\n      <div class=\"fb-filter\"><span>tcp.port == 445 && ip.src != ip.dst</span><span class=\"fb-desc\">SMB between hosts — lateral movement indicator</span></div>\n      <div class=\"fb-filter\"><span>kerberos</span><span class=\"fb-desc\">Kerberos authentication — TGT/TGS requests, AS-REP</span></div>\n      <div class=\"fb-filter\"><span>ntlmssp</span><span class=\"fb-desc\">NTLM auth — Pass-the-Hash indicator</span></div>\n      <div class=\"fb-filter\"><span>tcp.port == 3389</span><span class=\"fb-desc\">RDP — remote desktop lateral movement</span></div>\n    </div>\n  </div>\n\n  <!-- tshark scripting -->\n  <div class=\"g2\" style=\"margin-bottom:14px\">\n    <div class=\"card cs\">\n      <div class=\"clabel\">tshark — Command Line Power</div>\n      <div class=\"ctitle sonar\">TSHARK EXTRACTION SCRIPTS</div>\n      <div class=\"cb\">\n<span class=\"tag\">BASH</span>\n<span class=\"C\"># Extract all HTTP objects (files downloaded over HTTP)</span>\n<span class=\"K\">tshark</span> -r cap.pcap --export-objects http,./extracted/\n\n<span class=\"C\"># Extract all DNS queries + responses</span>\n<span class=\"K\">tshark</span> -r cap.pcap -Y dns -T fields \\\n    -e frame.time -e dns.qry.name \\\n    -e dns.resp.addr -e dns.flags.rcode \\\n    -E header=y -E separator=, > dns_full.csv\n\n<span class=\"C\"># Extract TLS SNI values (encrypted traffic server names)</span>\n<span class=\"K\">tshark</span> -r cap.pcap -Y tls.handshake.type==1 \\\n    -T fields -e ip.src -e ip.dst \\\n    -e tls.handshake.extensions_server_name\n\n<span class=\"C\"># Unique external IPs contacted</span>\n<span class=\"K\">tshark</span> -r cap.pcap -T fields -e ip.dst \\\n    | <span class=\"K\">grep</span> -vE '^(10\\.|192\\.168\\.|172\\.(1[6-9]|2[0-9]|3[01])\\.)' \\\n    | <span class=\"K\">sort -u</span>\n\n<span class=\"C\"># HTTP User-Agent strings</span>\n<span class=\"K\">tshark</span> -r cap.pcap -Y http.request \\\n    -T fields -e http.host -e http.user_agent \\\n    -E separator='|' | <span class=\"K\">sort -u</span>\n\n<span class=\"C\"># Top talkers by byte volume</span>\n<span class=\"K\">tshark</span> -r cap.pcap -q -z conv,ip \\\n    | <span class=\"K\">sort</span> -k5 -rn | head -20</div>\n    </div>\n    <div class=\"card cs\">\n      <div class=\"clabel\">Python — Scapy / PyShark</div>\n      <div class=\"ctitle sonar\">PROGRAMMATIC PCAP ANALYSIS</div>\n      <div class=\"cb\">\n<span class=\"tag\">PYTHON</span>\n<span class=\"K\">import</span> pyshark\n<span class=\"K\">from</span> collections <span class=\"K\">import</span> Counter, defaultdict\n<span class=\"K\">import</span> math, ipaddress\n\n<span class=\"K\">def</span> <span class=\"F\">analyze_pcap</span>(pcap_path: str):\n    cap = pyshark.FileCapture(pcap_path,\n        display_filter=<span class=\"S\">'dns || http || tls'</span>)\n\n    dns_queries  = Counter()\n    http_hosts   = Counter()\n    tls_sni      = Counter()\n    nxdomains    = []\n\n    <span class=\"K\">for</span> pkt <span class=\"K\">in</span> cap:\n        <span class=\"K\">try</span>:\n            <span class=\"C\"># DNS analysis</span>\n            <span class=\"K\">if</span> hasattr(pkt, <span class=\"S\">'dns'</span>):\n                q = pkt.dns.qry_name\n                dns_queries[q] += <span class=\"N\">1</span>\n                <span class=\"K\">if</span> hasattr(pkt.dns, <span class=\"S\">'flags_rcode'</span>) \\\n                   <span class=\"K\">and</span> pkt.dns.flags_rcode == <span class=\"S\">'3'</span>:\n                    nxdomains.append(q)\n\n            <span class=\"C\"># HTTP analysis</span>\n            <span class=\"K\">if</span> hasattr(pkt, <span class=\"S\">'http'</span>):\n                <span class=\"K\">if</span> hasattr(pkt.http, <span class=\"S\">'host'</span>):\n                    http_hosts[pkt.http.host] += <span class=\"N\">1</span>\n\n            <span class=\"C\"># TLS SNI analysis</span>\n            <span class=\"K\">if</span> hasattr(pkt, <span class=\"S\">'tls'</span>):\n                sni = getattr(pkt.tls,\n                    <span class=\"S\">'handshake_extensions_server_name'</span>, None)\n                <span class=\"K\">if</span> sni:\n                    tls_sni[sni] += <span class=\"N\">1</span>\n        <span class=\"K\">except</span>: <span class=\"K\">pass</span>\n\n    <span class=\"F\">print</span>(f<span class=\"S\">\"\\nNXDOMAIN count: {len(nxdomains)}\"</span>)\n    <span class=\"F\">print</span>(f<span class=\"S\">\"Unique DNS queries: {len(dns_queries)}\"</span>)\n    <span class=\"F\">print</span>(<span class=\"S\">\"\\nTop HTTP hosts:\"</span>)\n    <span class=\"K\">for</span> h, c <span class=\"K\">in</span> http_hosts.most_common(<span class=\"N\">10</span>):\n        <span class=\"F\">print</span>(f<span class=\"S\">\"  {c:5d}  {h}\"</span>)\n    <span class=\"F\">print</span>(<span class=\"S\">\"\\nTLS SNI (external):\"</span>)\n    <span class=\"K\">for</span> s, c <span class=\"K\">in</span> tls_sni.most_common(<span class=\"N\">10</span>):\n        <span class=\"F\">print</span>(f<span class=\"S\">\"  {c:5d}  {s}\"</span>)\n\nanalyze_pcap(<span class=\"S\">\"capture.pcap\"</span>)</div>\n    </div>\n  </div>\n\n  <!-- File extraction -->\n  <div class=\"card\">\n    <div class=\"clabel\">Artifact Extraction</div>\n    <div class=\"ctitle\">EXTRACTING FILES & CREDENTIALS FROM PCAP</div>\n    <div class=\"cb\">\n<span class=\"C\"># Export HTTP objects in Wireshark: File → Export Objects → HTTP</span>\n<span class=\"C\"># Command line equivalent:</span>\n<span class=\"K\">tshark</span> -r cap.pcap --export-objects http,./http_objects/\n<span class=\"K\">tshark</span> -r cap.pcap --export-objects smb,./smb_objects/\n<span class=\"K\">tshark</span> -r cap.pcap --export-objects tftp,./tftp_objects/\n\n<span class=\"C\"># Hash all extracted files for VT lookup</span>\n<span class=\"K\">find</span> ./http_objects/ -type f -exec sha256sum {} \\;\n\n<span class=\"C\"># Extract NTLM hashes from SMB/HTTP traffic (for analysis)</span>\n<span class=\"C\"># Useful during forensics to identify credential theft attempts</span>\n<span class=\"K\">python3</span> -m PCredz -f cap.pcap\n<span class=\"C\"># Extracts: NTLM NTHash, Kerberos tickets, HTTP Basic, FTP creds</span>\n\n<span class=\"C\"># Follow TCP stream for specific conversation</span>\n<span class=\"C\"># Wireshark: right-click packet → Follow → TCP Stream</span>\n<span class=\"C\"># tshark equivalent (stream index from -z conv,tcp output):</span>\n<span class=\"K\">tshark</span> -r cap.pcap -Y \"tcp.stream == 42\" \\\n    -T fields -e data.data | <span class=\"K\">xxd</span>\n\n<span class=\"C\"># Reassemble a transferred file from TCP stream</span>\n<span class=\"K\">tcpflow</span> -r cap.pcap -C -g       <span class=\"C\"># reassembles all TCP flows</span>\n<span class=\"K\">networkx</span>                         <span class=\"C\"># or use Wireshark → Export → Objects</span></div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════ ZEEK ══════════════ -->\n<div class=\"module z1\" id=\"mod-zeek\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">02</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Network Security Monitoring //</div>\n      <div class=\"sh-title\">Zeek <span class=\"hl\">Log Analysis</span></div>\n      <div class=\"sh-desc\">Zeek converts raw PCAPs into structured, analyst-friendly logs. Each protocol gets its own log file. Correlation across logs surfaces attack chains invisible in raw packets.</div>\n    </div>\n  </div>\n\n  <!-- Zeek log types -->\n  <div class=\"card cp\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Zeek Log Reference</div>\n    <div class=\"ctitle ping\">ZEEK LOG FILES — COMPLETE REFERENCE</div>\n    <div class=\"cbody\" style=\"margin-bottom:10px\">Every Zeek analysis session produces these logs. Learn which log to consult for each investigation question.</div>\n    <table class=\"dtable\">\n      <tr><th>LOG FILE</th><th>KEY FIELDS</th><th>FORENSIC QUESTIONS ANSWERED</th></tr>\n      <tr>\n        <td><strong>conn.log</strong></td>\n        <td><code>uid, orig_h, orig_p, resp_h, resp_p, proto, service, duration, orig_bytes, resp_bytes, conn_state</code></td>\n        <td>Who talked to whom? For how long? How much data? (Primary beaconing analysis)</td>\n      </tr>\n      <tr>\n        <td><strong>dns.log</strong></td>\n        <td><code>query, qtype_name, answers, rcode_name, TTL, rejected</code></td>\n        <td>What domains were queried? NXDOMAIN storms? DGA? DNS tunneling?</td>\n      </tr>\n      <tr>\n        <td><strong>http.log</strong></td>\n        <td><code>host, uri, method, user_agent, status_code, request_body_len, response_body_len, referrer</code></td>\n        <td>C2 HTTP beacons? File downloads? Malicious User-Agents? Data exfil?</td>\n      </tr>\n      <tr>\n        <td><strong>ssl.log</strong></td>\n        <td><code>server_name, version, cipher, ja3, ja3s, cert_chain_fuids, validation_status</code></td>\n        <td>Self-signed certs? Unusual TLS versions? JA3 fingerprint matches known malware?</td>\n      </tr>\n      <tr>\n        <td><strong>files.log</strong></td>\n        <td><code>fuid, tx_hosts, rx_hosts, mime_type, filename, md5, sha256, extracted</code></td>\n        <td>What files were transferred? Are their hashes malicious? What MIME types?</td>\n      </tr>\n      <tr>\n        <td><strong>smtp.log</strong></td>\n        <td><code>from, to, subject, x_originating_ip, attachment_info</code></td>\n        <td>Phishing email metadata, spoofed senders, malicious attachments</td>\n      </tr>\n      <tr>\n        <td><strong>smb_files.log</strong></td>\n        <td><code>action, path, name, size, times</code></td>\n        <td>Files accessed/written over SMB — ransomware file activity, lateral tools</td>\n      </tr>\n      <tr>\n        <td><strong>smb_mapping.log</strong></td>\n        <td><code>path, resource_type, share_type</code></td>\n        <td>Network share access — lateral movement, data staging</td>\n      </tr>\n      <tr>\n        <td><strong>weird.log</strong></td>\n        <td><code>peer, name, addl</code></td>\n        <td>Protocol anomalies Zeek flagged — often high-value alerts</td>\n      </tr>\n      <tr>\n        <td><strong>notice.log</strong></td>\n        <td><code>note, msg, src, dst, sub</code></td>\n        <td>Zeek-generated alerts from loaded policy scripts</td>\n      </tr>\n    </table>\n  </div>\n\n  <!-- Zeek analysis commands -->\n  <div class=\"g2\" style=\"margin-bottom:14px\">\n    <div class=\"card cp\">\n      <div class=\"clabel\">Zeek CLI — zeek-cut</div>\n      <div class=\"ctitle ping\">ZEEK LOG ANALYSIS COMMANDS</div>\n      <div class=\"cb\">\n<span class=\"tag\">BASH</span>\n<span class=\"C\"># Run Zeek against a PCAP</span>\n<span class=\"K\">zeek</span> -r capture.pcap local\n\n<span class=\"C\"># zeek-cut: select specific fields (like awk but aware of Zeek headers)</span>\n\n<span class=\"C\"># Top DNS queries (excluding reverse lookups)</span>\n<span class=\"K\">cat</span> dns.log | <span class=\"K\">zeek-cut</span> query rcode_name \\\n    | <span class=\"K\">grep</span> -v \".arpa\" \\\n    | <span class=\"K\">sort | uniq -c | sort -rn</span> | head -20\n\n<span class=\"C\"># NXDOMAIN storm detection</span>\n<span class=\"K\">cat</span> dns.log | <span class=\"K\">zeek-cut</span> query rcode_name \\\n    | <span class=\"K\">awk</span> '$2==\"NXDOMAIN\"' \\\n    | <span class=\"K\">cut -f1</span> | <span class=\"K\">sort | uniq -c | sort -rn</span>\n\n<span class=\"C\"># Suspicious HTTP connections (unusual UA + POST)</span>\n<span class=\"K\">cat</span> http.log | <span class=\"K\">zeek-cut</span> host uri method user_agent \\\n    | <span class=\"K\">awk</span> '$3==\"POST\"' \\\n    | <span class=\"K\">grep</span> -v \"Mozilla\\|Chrome\\|Safari\"\n\n<span class=\"C\"># Self-signed or invalid TLS certificates</span>\n<span class=\"K\">cat</span> ssl.log | <span class=\"K\">zeek-cut</span> server_name ja3 ja3s validation_status \\\n    | <span class=\"K\">grep</span> -v \"ok\"\n\n<span class=\"C\"># Large outbound transfers (potential exfil)</span>\n<span class=\"K\">cat</span> conn.log | <span class=\"K\">zeek-cut</span> orig_h resp_h orig_bytes resp_bytes service \\\n    | <span class=\"K\">awk</span> '$4>1000000' \\\n    | <span class=\"K\">sort -t$'\\t' -k4 -rn</span> | head -20\n\n<span class=\"C\"># SMB connections between internal hosts (lateral movement)</span>\n<span class=\"K\">cat</span> conn.log | <span class=\"K\">zeek-cut</span> orig_h resp_h resp_p service \\\n    | <span class=\"K\">awk</span> '$4==\"445\" && /^192\\.168/'</div>\n    </div>\n\n    <div class=\"card cp\">\n      <div class=\"clabel\">Zeek Scripting</div>\n      <div class=\"ctitle ping\">CUSTOM ZEEK DETECTION SCRIPT</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">Write Zeek scripts to detect custom behavioral patterns. This script detects beaconing by tracking connection intervals per host.</div>\n      <div class=\"cb\">\n<span class=\"tag\">ZEEK SCRIPT</span>\n<span class=\"C\">## beacon_detect.zeek</span>\n<span class=\"C\">## Detect C2 beaconing: regular intervals to same external IP</span>\n\n<span class=\"K\">module</span> BeaconDetect;\n\n<span class=\"K\">export</span> {\n    <span class=\"K\">const</span> beacon_threshold = <span class=\"N\">8</span> &amp;redef;   <span class=\"C\"># min connections</span>\n    <span class=\"K\">const</span> jitter_tolerance = <span class=\"N\">0.2</span> &amp;redef; <span class=\"C\"># 20% jitter allowed</span>\n}\n\n<span class=\"C\"># Track connection times per src->dst pair</span>\n<span class=\"K\">global</span> conn_times: table[addr, addr] <span class=\"K\">of</span> vector of time;\n\n<span class=\"K\">event</span> <span class=\"F\">connection_established</span>(c: connection) {\n    <span class=\"K\">local</span> orig = c$id$orig_h;\n    <span class=\"K\">local</span> resp = c$id$resp_h;\n\n    <span class=\"C\"># Only track external destinations</span>\n    <span class=\"K\">if</span> ( resp in Site::private_address_space ) <span class=\"K\">return</span>;\n\n    <span class=\"K\">if</span> ( [orig, resp] !<span class=\"K\">in</span> conn_times )\n        conn_times[orig, resp] = vector();\n    conn_times[orig, resp] += network_time();\n}\n\n<span class=\"K\">event</span> <span class=\"F\">zeek_done</span>() {\n    <span class=\"K\">for</span> ( [src, dst] <span class=\"K\">in</span> conn_times ) {\n        <span class=\"K\">local</span> times = conn_times[src, dst];\n        <span class=\"K\">if</span> ( |times| &lt; beacon_threshold ) <span class=\"K\">next</span>;\n\n        <span class=\"C\"># Calculate inter-arrival time deltas</span>\n        <span class=\"K\">local</span> deltas: vector of double;\n        <span class=\"K\">for</span> ( i <span class=\"K\">in</span> times ) {\n            <span class=\"K\">if</span> ( i == 0 ) <span class=\"K\">next</span>;\n            deltas += interval_to_double(times[i] - times[i-<span class=\"N\">1</span>]);\n        }\n        <span class=\"C\"># Low coefficient of variation = regular = beacon</span>\n        <span class=\"K\">local</span> mean   = mean(deltas);\n        <span class=\"K\">local</span> stddev = stddev(deltas);\n        <span class=\"K\">local</span> cv = stddev / mean;  <span class=\"C\"># coefficient of variation</span>\n        <span class=\"K\">if</span> ( cv &lt; jitter_tolerance ) {\n            <span class=\"F\">NOTICE</span>([$note=Weird::Activity,\n                $msg=fmt(<span class=\"S\">\"BEACON: %s→%s interval=%.1fs cv=%.3f count=%d\"</span>,\n                    src, dst, mean, cv, |times|),\n                $src=src, $dst=dst]);\n        }\n    }\n}</div>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════ SURICATA ══════════════ -->\n<div class=\"module z1\" id=\"mod-suricata\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">03</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Network Intrusion Detection //</div>\n      <div class=\"sh-title\">Suricata <span class=\"hl\">Rule Authoring</span></div>\n      <div class=\"sh-desc\">Writing high-fidelity Suricata rules for network-level detection. Rule anatomy, protocol keywords, flow tracking, byte matching, and performance tuning.</div>\n    </div>\n  </div>\n\n  <!-- Rule anatomy -->\n  <div class=\"card cw\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Suricata Rule — Complete Anatomy</div>\n    <div class=\"ctitle warn\">RULE STRUCTURE ANNOTATED</div>\n    <div class=\"cb\" style=\"--cb-accent:var(--warn)\">\n<span class=\"tag\">SURICATA</span>\n<span class=\"C\"># Suricata rule format:</span>\n<span class=\"C\"># action proto src_ip src_port direction dst_ip dst_port (options)</span>\n\n<span class=\"K\">alert</span>  <span class=\"F\">tcp</span>  <span class=\"S\">$HOME_NET</span>  <span class=\"N\">any</span>  <span class=\"W\">-&gt;</span>  <span class=\"S\">$EXTERNAL_NET</span>  <span class=\"N\">443</span>  (\n    <span class=\"C\"># Rule identification</span>\n    <span class=\"V\">msg</span>:<span class=\"S\">\"C2 Beacon Pattern — Regular HTTPS POST\"</span>;\n    <span class=\"V\">sid</span>:<span class=\"N\">9000001</span>;           <span class=\"C\"># unique rule ID</span>\n    <span class=\"V\">rev</span>:<span class=\"N\">2</span>;                 <span class=\"C\"># revision number</span>\n    <span class=\"V\">classtype</span>:trojan-activity;\n\n    <span class=\"C\"># Protocol / flow specification</span>\n    <span class=\"V\">flow</span>:established,to_server;  <span class=\"C\"># established TCP, to external</span>\n\n    <span class=\"C\"># Application layer detection</span>\n    <span class=\"V\">app-layer-protocol</span>:tls;    <span class=\"C\"># TLS traffic only</span>\n\n    <span class=\"C\"># TLS-specific keywords</span>\n    <span class=\"V\">tls.sni</span>; <span class=\"V\">content</span>:<span class=\"S\">\"malicious-domain.com\"</span>; <span class=\"V\">nocase</span>;\n\n    <span class=\"C\"># Byte pattern matching</span>\n    <span class=\"V\">content</span>:<span class=\"S\">\"|16 03|\"</span>; <span class=\"V\">depth</span>:<span class=\"N\">2</span>;   <span class=\"C\"># TLS record header</span>\n\n    <span class=\"C\"># PCRE for complex patterns</span>\n    <span class=\"V\">pcre</span>:<span class=\"S\">\"/^POST\\s+\\/[a-z]{8,12}\\.php/i\"</span>;\n\n    <span class=\"C\"># Threshold: alert only every 60s per src</span>\n    <span class=\"V\">threshold</span>:type limit, track by_src, count 1, seconds 60;\n\n    <span class=\"C\"># Metadata</span>\n    <span class=\"V\">metadata</span>:attack_target Client_Endpoint,\n              affected_product Windows,\n              mitre_tactic_id TA0011,\n              mitre_technique_id T1071.001;\n)</div>\n  </div>\n\n  <!-- Production rules -->\n  <div class=\"g2\" style=\"margin-bottom:14px\">\n\n    <div class=\"card cw\">\n      <div class=\"clabel\">Rule 01 — DNS Tunneling</div>\n      <div class=\"ctitle warn\">DETECT DNS TUNNELING</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--warn)\">\n<span class=\"C\"># DNS tunneling: data encoded in long subdomains</span>\n<span class=\"K\">alert</span> <span class=\"F\">dns</span> any any -> any 53 (\n    <span class=\"V\">msg</span>:<span class=\"S\">\"Possible DNS Tunneling — Long Label\"</span>;\n    <span class=\"V\">dns.query</span>;\n    <span class=\"V\">content</span>:<span class=\"S\">\".\"</span>;\n    <span class=\"C\"># Label longer than 30 chars</span>\n    <span class=\"V\">pcre</span>:<span class=\"S\">\"/(?:^|\\.)[A-Za-z0-9+\\/=]{30,}(?:\\.|$)/\"</span>;\n    <span class=\"V\">threshold</span>:type both, track by_src,\n               count 10, seconds 60;\n    <span class=\"V\">sid</span>:<span class=\"N\">9000002</span>; <span class=\"V\">rev</span>:<span class=\"N\">1</span>;\n    <span class=\"V\">classtype</span>:policy-violation;\n)\n\n<span class=\"C\"># DNS TXT record queries (used for data exfil)</span>\n<span class=\"K\">alert</span> <span class=\"F\">dns</span> $HOME_NET any -> any 53 (\n    <span class=\"V\">msg</span>:<span class=\"S\">\"DNS TXT Record Query — Potential Tunneling\"</span>;\n    <span class=\"V\">dns.query</span>;\n    <span class=\"V\">byte_test</span>:<span class=\"N\">2</span>,=,<span class=\"N\">0x0010</span>,<span class=\"N\">0</span>,relative; <span class=\"C\"># qtype=TXT (0x0010)</span>\n    <span class=\"V\">threshold</span>:type limit, track by_src,\n               count 1, seconds 300;\n    <span class=\"V\">sid</span>:<span class=\"N\">9000003</span>; <span class=\"V\">rev</span>:<span class=\"N\">1</span>;\n)</div>\n    </div>\n\n    <div class=\"card cw\">\n      <div class=\"clabel\">Rule 02 — Malware User-Agents</div>\n      <div class=\"ctitle warn\">DETECT MALICIOUS HTTP PATTERNS</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--warn)\">\n<span class=\"C\"># Detect common RAT/beacon User-Agents</span>\n<span class=\"K\">alert</span> <span class=\"F\">http</span> $HOME_NET any -> $EXTERNAL_NET any (\n    <span class=\"V\">msg</span>:<span class=\"S\">\"Suspicious HTTP User-Agent — Known Malware\"</span>;\n    <span class=\"V\">flow</span>:established,to_server;\n    <span class=\"V\">http.user_agent</span>;\n    <span class=\"V\">content</span>:<span class=\"S\">\"python-requests\"</span>; <span class=\"V\">nocase</span>;\n    <span class=\"V\">sid</span>:<span class=\"N\">9000004</span>; <span class=\"V\">rev</span>:<span class=\"N\">1</span>;\n)\n\n<span class=\"C\"># Detect HTTP POST with no Referer (C2 beacons)</span>\n<span class=\"K\">alert</span> <span class=\"F\">http</span> $HOME_NET any -> $EXTERNAL_NET any (\n    <span class=\"V\">msg</span>:<span class=\"S\">\"HTTP POST with No Referer — C2 Indicator\"</span>;\n    <span class=\"V\">flow</span>:established,to_server;\n    <span class=\"V\">http.method</span>; <span class=\"V\">content</span>:<span class=\"S\">\"POST\"</span>;\n    <span class=\"V\">http.header_names</span>;\n    <span class=\"V\">content</span>:!<span class=\"S\">\"Referer\"</span>; <span class=\"V\">nocase</span>;\n    <span class=\"V\">http.request_body</span>; <span class=\"V\">dsize</span>:&gt;<span class=\"N\">100</span>;\n    <span class=\"V\">threshold</span>:type both, track by_src,\n               count 5, seconds 60;\n    <span class=\"V\">sid</span>:<span class=\"N\">9000005</span>; <span class=\"V\">rev</span>:<span class=\"N\">1</span>;\n)\n\n<span class=\"C\"># Detect cleartext credential submission</span>\n<span class=\"K\">alert</span> <span class=\"F\">http</span> any any -> $HTTP_SERVERS any (\n    <span class=\"V\">msg</span>:<span class=\"S\">\"HTTP POST — Possible Cleartext Credentials\"</span>;\n    <span class=\"V\">flow</span>:established,to_server;\n    <span class=\"V\">http.method</span>; <span class=\"V\">content</span>:<span class=\"S\">\"POST\"</span>;\n    <span class=\"V\">http.request_body</span>;\n    <span class=\"V\">content</span>:<span class=\"S\">\"password\"</span>; <span class=\"V\">nocase</span>;\n    <span class=\"V\">pcre</span>:<span class=\"S\">\"/password=(?!%|&amp;)/i\"</span>;\n    <span class=\"V\">sid</span>:<span class=\"N\">9000006</span>; <span class=\"V\">rev</span>:<span class=\"N\">1</span>;\n)</div>\n    </div>\n\n  </div>\n\n  <!-- Suricata EVE JSON -->\n  <div class=\"card\">\n    <div class=\"clabel\">Suricata Output & SIEM Integration</div>\n    <div class=\"ctitle\">EVE JSON — PARSING SURICATA ALERTS</div>\n    <div class=\"cb\">\n<span class=\"tag\">PYTHON</span>\n<span class=\"C\"># Parse Suricata EVE JSON log for high-priority alerts</span>\n<span class=\"K\">import</span> json, sys\n<span class=\"K\">from</span> datetime <span class=\"K\">import</span> datetime\n<span class=\"K\">from</span> collections <span class=\"K\">import</span> Counter\n\n<span class=\"K\">def</span> <span class=\"F\">parse_eve</span>(eve_log: str):\n    alerts = []\n    severity_counts = Counter()\n\n    <span class=\"K\">with</span> open(eve_log) <span class=\"K\">as</span> f:\n        <span class=\"K\">for</span> line <span class=\"K\">in</span> f:\n            <span class=\"K\">try</span>:\n                ev = json.loads(line)\n                <span class=\"K\">if</span> ev.get(<span class=\"S\">'event_type'</span>) != <span class=\"S\">'alert'</span>: <span class=\"K\">continue</span>\n\n                alert = ev[<span class=\"S\">'alert'</span>]\n                sev   = alert.get(<span class=\"S\">'severity'</span>, <span class=\"N\">3</span>)\n                severity_counts[sev] += <span class=\"N\">1</span>\n\n                <span class=\"K\">if</span> sev <= <span class=\"N\">2</span>:  <span class=\"C\"># HIGH / CRITICAL only</span>\n                    alerts.append({\n                        <span class=\"S\">'ts'</span>:       ev.get(<span class=\"S\">'timestamp'</span>),\n                        <span class=\"S\">'src'</span>:      ev.get(<span class=\"S\">'src_ip'</span>),\n                        <span class=\"S\">'dst'</span>:      ev.get(<span class=\"S\">'dest_ip'</span>),\n                        <span class=\"S\">'sport'</span>:    ev.get(<span class=\"S\">'src_port'</span>),\n                        <span class=\"S\">'dport'</span>:    ev.get(<span class=\"S\">'dest_port'</span>),\n                        <span class=\"S\">'msg'</span>:      alert.get(<span class=\"S\">'signature'</span>),\n                        <span class=\"S\">'sid'</span>:      alert.get(<span class=\"S\">'signature_id'</span>),\n                        <span class=\"S\">'category'</span>: alert.get(<span class=\"S\">'category'</span>),\n                        <span class=\"S\">'proto'</span>:    ev.get(<span class=\"S\">'proto'</span>),\n                    })\n            <span class=\"K\">except</span>: <span class=\"K\">pass</span>\n\n    <span class=\"F\">print</span>(f<span class=\"S\">\"Total alerts: {sum(severity_counts.values())}\"</span>)\n    <span class=\"F\">print</span>(f<span class=\"S\">\"Critical/High: {severity_counts[1] + severity_counts[2]}\"</span>)\n    <span class=\"F\">print</span>(<span class=\"S\">\"\\nTop alerts:\"</span>)\n    msg_counts = Counter(a[<span class=\"S\">'msg'</span>] <span class=\"K\">for</span> a <span class=\"K\">in</span> alerts)\n    <span class=\"K\">for</span> msg, cnt <span class=\"K\">in</span> msg_counts.most_common(<span class=\"N\">10</span>):\n        <span class=\"F\">print</span>(f<span class=\"S\">\"  {cnt:4d}  {msg}\"</span>)\n\n    <span class=\"K\">return</span> alerts\n\nalerts = parse_eve(<span class=\"S\">\"eve.json\"</span>)</div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════ DNS FORENSICS ══════════════ -->\n<div class=\"module z1\" id=\"mod-dns\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">04</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// The Overlooked Protocol //</div>\n      <div class=\"sh-title\">DNS <span class=\"hl\">Forensics</span></div>\n      <div class=\"sh-desc\">DNS is the most information-rich protocol in the network analyst's toolkit — and the most abused. DGA detection, DNS tunneling forensics, passive DNS correlation, and covert channel analysis.</div>\n    </div>\n  </div>\n\n  <div class=\"g2\" style=\"margin-bottom:14px\">\n\n    <div class=\"card cp\">\n      <div class=\"clabel\">DGA Detection</div>\n      <div class=\"ctitle ping\">DETECTING DOMAIN GENERATION ALGORITHMS</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">DGA-generated domains have characteristic statistical properties — high entropy, unusual length distribution, and distinctive character n-gram patterns.</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--ping2)\">\n<span class=\"tag\">PYTHON</span>\n<span class=\"K\">import</span> math, re\n<span class=\"K\">from</span> collections <span class=\"K\">import</span> Counter\n\n<span class=\"K\">def</span> <span class=\"F\">domain_entropy</span>(domain: str) -> float:\n    <span class=\"S\">\"\"\"Shannon entropy of the second-level domain.\"\"\"</span>\n    sld = domain.split(<span class=\"S\">'.'</span>)[<span class=\"N\">0</span>]  <span class=\"C\"># e.g. 'k3mq9xzt4' from 'k3mq9xzt4.com'</span>\n    freq = Counter(sld)\n    total = len(sld)\n    <span class=\"K\">return</span> -sum(c/total * math.log2(c/total) <span class=\"K\">for</span> c <span class=\"K\">in</span> freq.values())\n\n<span class=\"C\"># Consonant-to-vowel ratio (DGA domains have high ratio)</span>\n<span class=\"K\">def</span> <span class=\"F\">consonant_ratio</span>(domain: str) -> float:\n    sld = domain.split(<span class=\"S\">'.'</span>)[<span class=\"N\">0</span>].lower()\n    vowels = set(<span class=\"S\">'aeiou'</span>)\n    consonants = [c <span class=\"K\">for</span> c <span class=\"K\">in</span> sld <span class=\"K\">if</span> c.isalpha() <span class=\"K\">and</span> c <span class=\"K\">not in</span> vowels]\n    letters = [c <span class=\"K\">for</span> c <span class=\"K\">in</span> sld <span class=\"K\">if</span> c.isalpha()]\n    <span class=\"K\">return</span> len(consonants)/len(letters) <span class=\"K\">if</span> letters <span class=\"K\">else</span> <span class=\"N\">0</span>\n\n<span class=\"K\">def</span> <span class=\"F\">is_dga</span>(domain: str) -> dict:\n    sld = domain.split(<span class=\"S\">'.'</span>)[<span class=\"N\">0</span>]\n    ent = domain_entropy(domain)\n    cvr = consonant_ratio(domain)\n    length = len(sld)\n    has_digits = bool(re.search(<span class=\"S\">r'\\d'</span>, sld))\n\n    score = <span class=\"N\">0</span>\n    reasons = []\n    <span class=\"K\">if</span> ent > <span class=\"N\">3.5</span>:    score += <span class=\"N\">2</span>; reasons.append(f<span class=\"S\">\"high entropy={ent:.2f}\"</span>)\n    <span class=\"K\">if</span> cvr > <span class=\"N\">0.75</span>:   score += <span class=\"N\">2</span>; reasons.append(f<span class=\"S\">\"high consonants={cvr:.2f}\"</span>)\n    <span class=\"K\">if</span> length > <span class=\"N\">15</span>:  score += <span class=\"N\">1</span>; reasons.append(f<span class=\"S\">\"long label={length}\"</span>)\n    <span class=\"K\">if</span> has_digits:   score += <span class=\"N\">1</span>; reasons.append(<span class=\"S\">\"contains digits\"</span>)\n\n    <span class=\"K\">return</span> {<span class=\"S\">\"domain\"</span>: domain, <span class=\"S\">\"score\"</span>: score,\n            <span class=\"S\">\"dga_likely\"</span>: score >= <span class=\"N\">4</span>, <span class=\"S\">\"reasons\"</span>: reasons}\n\n<span class=\"C\"># Test against DNS log</span>\n<span class=\"K\">with</span> open(<span class=\"S\">\"dns.log\"</span>) <span class=\"K\">as</span> f:\n    <span class=\"K\">for</span> line <span class=\"K\">in</span> f:\n        <span class=\"K\">if</span> line.startswith(<span class=\"S\">'#'</span>): <span class=\"K\">continue</span>\n        fields = line.split(<span class=\"S\">'\\t'</span>)\n        <span class=\"K\">if</span> len(fields) < <span class=\"N\">10</span>: <span class=\"K\">continue</span>\n        domain = fields[<span class=\"N\">9</span>]  <span class=\"C\"># query field</span>\n        result = is_dga(domain)\n        <span class=\"K\">if</span> result[<span class=\"S\">\"dga_likely\"</span>]:\n            <span class=\"F\">print</span>(f<span class=\"S\">\"[DGA?] {domain} — {result['reasons']}\"</span>)</div>\n    </div>\n\n    <div class=\"card cp\">\n      <div class=\"clabel\">DNS Tunneling Analysis</div>\n      <div class=\"ctitle ping\">DETECTING DNS DATA EXFILTRATION</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">DNS tunneling encodes data in subdomains or TXT records. Detection requires volume analysis, label length analysis, and entropy measurement.</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--ping2)\">\n<span class=\"tag\">BASH + PYTHON</span>\n<span class=\"C\"># Step 1: Find domains with many unique subdomains</span>\n<span class=\"C\"># (legitimate CDNs have many subdomains, but not per-query unique)</span>\n<span class=\"K\">cat</span> dns.log | <span class=\"K\">zeek-cut</span> query \\\n    | <span class=\"K\">awk</span> -F. '{\n        n=NF; parent=$2\".\"$NF;\n        if(NF>2) parent=$(NF-1)\".\"$NF;\n        subs[parent]++\n      } END {\n        for(p in subs) if(subs[p]>50) print subs[p], p\n      }' | <span class=\"K\">sort -rn</span>\n\n<span class=\"C\"># Step 2: Measure query byte rate per src IP</span>\n<span class=\"K\">python3</span> -c <span class=\"S\">\"\nimport re\nfrom collections import defaultdict\n\ndns_bytes = defaultdict(int)\nwith open('dns.log') as f:\n    for line in f:\n        if line.startswith('#'): continue\n        parts = line.split('\\t')\n        if len(parts) < 10: continue\n        src_ip = parts[2]           # orig_h\n        query  = parts[9]           # query field\n        dns_bytes[src_ip] += len(query)\n\nfor ip, total in sorted(dns_bytes.items(), key=lambda x:-x[1])[:10]:\n    print(f'{total:8d} bytes  {ip}')\n# High DNS query bytes/host = tunneling candidate\n\"</span>\n\n<span class=\"C\"># Step 3: Decode suspected base64 in subdomains</span>\n<span class=\"K\">cat</span> dns.log | <span class=\"K\">zeek-cut</span> query \\\n    | <span class=\"K\">grep</span> -oE '[A-Za-z0-9+/=]{20,}' \\\n    | <span class=\"K\">while read</span> enc; <span class=\"K\">do</span>\n        decoded=$(<span class=\"K\">echo</span> \"$enc\" | <span class=\"K\">base64</span> -d 2>/dev/null)\n        [[ -n \"$decoded\" ]] && <span class=\"K\">echo</span> \"$enc → $decoded\"\n      <span class=\"K\">done</span></div>\n    </div>\n\n  </div>\n\n  <div class=\"card\">\n    <div class=\"clabel\">Passive DNS Correlation</div>\n    <div class=\"ctitle\">PASSIVE DNS INVESTIGATION WORKFLOW</div>\n    <div class=\"cb\">\n<span class=\"tag\">BASH</span>\n<span class=\"C\"># Passive DNS: correlate IP → all domains that resolved to it</span>\n<span class=\"C\"># From Zeek dns.log (within your capture):</span>\n<span class=\"K\">cat</span> dns.log | <span class=\"K\">zeek-cut</span> query answers \\\n    | <span class=\"K\">awk</span> '{\n        split($2, ans, \",\")\n        for(i in ans) print ans[i], $1\n      }' | <span class=\"K\">sort | uniq</span> > ip_to_domain.txt\n\n<span class=\"C\"># Now: look up a suspicious IP → all domains that pointed there</span>\n<span class=\"K\">grep</span> \"185.220.101.34\" ip_to_domain.txt\n\n<span class=\"C\"># External passive DNS sources:</span>\n<span class=\"C\"># VirusTotal → Relations tab → Passive DNS</span>\n<span class=\"C\"># SecurityTrails API:</span>\n<span class=\"K\">curl</span> -H <span class=\"S\">\"APIKEY: your_key\"</span> \\\n    \"https://api.securitytrails.com/v1/history/185.220.101.34/dns/a\"\n\n<span class=\"C\"># Shodan (IP to DNS history):</span>\n<span class=\"K\">shodan</span> host 185.220.101.34\n\n<span class=\"C\"># DNS timeline reconstruction from PCAP:</span>\n<span class=\"K\">tshark</span> -r cap.pcap -Y \"dns && dns.flags.response==1\" \\\n    -T fields -e frame.time -e dns.qry.name -e dns.a \\\n    | <span class=\"K\">sort</span> > dns_timeline.txt\n\n<span class=\"C\"># Find first time a malicious domain appeared in traffic:</span>\n<span class=\"K\">grep</span> \"malicious-domain.com\" dns_timeline.txt | head -1\n<span class=\"C\"># → Establishes earliest possible infection time</span></div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════ TLS / JA3 ══════════════ -->\n<div class=\"module z1\" id=\"mod-tls\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">05</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Encrypted Traffic Analysis //</div>\n      <div class=\"sh-title\">TLS Forensics & <span class=\"hl\">JA3 Fingerprinting</span></div>\n      <div class=\"sh-desc\">Even encrypted traffic leaves fingerprints. JA3 hashes the TLS ClientHello parameters to identify the client implementation — and specific malware families have recognizable JA3 signatures.</div>\n    </div>\n  </div>\n\n  <!-- JA3 explanation -->\n  <div class=\"card cs\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">JA3 — How It Works</div>\n    <div class=\"ctitle sonar\">TLS FINGERPRINTING METHODOLOGY</div>\n    <div class=\"cbody\" style=\"margin-bottom:12px\">JA3 extracts five fields from the TLS ClientHello, concatenates them with delimiters, and MD5-hashes the result. Different client implementations (malware families, browsers, OS TLS stacks) produce different JA3 values.</div>\n    <div class=\"g2\">\n      <div class=\"cb\" style=\"--cb-accent:var(--sonar2)\">\n<span class=\"tag\">PYTHON — JA3 CALCULATION</span>\n<span class=\"K\">import</span> hashlib\n\n<span class=\"K\">def</span> <span class=\"F\">compute_ja3</span>(\n    tls_version:   int,        <span class=\"C\"># e.g. 771 (TLS 1.2)</span>\n    cipher_suites: list,       <span class=\"C\"># e.g. [49196, 49195, ...]</span>\n    extensions:    list,       <span class=\"C\"># extension type IDs</span>\n    elliptic_curves: list,     <span class=\"C\"># supported groups</span>\n    ec_point_formats: list,    <span class=\"C\"># point format IDs</span>\n) -> str:\n    <span class=\"S\">\"\"\"\n    JA3 = MD5(SSLVersion,Ciphers,Extensions,EllipticCurves,EllipticCurveFormats)\n    Each list joined with '-', components joined with ','\n    GREASE values (0x?a?a) are excluded before hashing\n    \"\"\"</span>\n    GREASE = {0x0a0a,0x1a1a,0x2a2a,0x3a3a,0x4a4a,0x5a5a,\n              0x6a6a,0x7a7a,0x8a8a,0x9a9a,0xaaaa,0xbaba,\n              0xcaca,0xdada,0xeaea,0xfafa}\n\n    cs  = <span class=\"S\">\"-\"</span>.join(str(c) <span class=\"K\">for</span> c <span class=\"K\">in</span> cipher_suites <span class=\"K\">if</span> c <span class=\"K\">not in</span> GREASE)\n    ext = <span class=\"S\">\"-\"</span>.join(str(e) <span class=\"K\">for</span> e <span class=\"K\">in</span> extensions    <span class=\"K\">if</span> e <span class=\"K\">not in</span> GREASE)\n    ec  = <span class=\"S\">\"-\"</span>.join(str(c) <span class=\"K\">for</span> c <span class=\"K\">in</span> elliptic_curves <span class=\"K\">if</span> c <span class=\"K\">not in</span> GREASE)\n    epf = <span class=\"S\">\"-\"</span>.join(str(p) <span class=\"K\">for</span> p <span class=\"K\">in</span> ec_point_formats)\n\n    raw = <span class=\"S\">\",\"</span>.join([str(tls_version), cs, ext, ec, epf])\n    <span class=\"K\">return</span> hashlib.md5(raw.encode()).hexdigest()\n\n<span class=\"C\"># Example: Cobalt Strike default beacon JA3</span>\n<span class=\"C\"># JA3 = 72a7c4f777d392aa0a9b06b6d20dc79f</span>\n<span class=\"C\"># Zeek extracts this automatically in ssl.log ja3 field</span></div>\n      <div>\n        <div class=\"cbody\" style=\"margin-bottom:12px\"><strong>Key JA3 databases and lookups:</strong></div>\n        <table class=\"dtable\">\n          <tr><th>JA3 HASH</th><th>KNOWN TOOL</th><th>VERDICT</th></tr>\n          <tr><td><code>72a7c4f7...</code></td><td>Cobalt Strike (default)</td><td class=\"tc-r\">MALWARE C2</td></tr>\n          <tr><td><code>a0e9f5d6...</code></td><td>Metasploit Meterpreter</td><td class=\"tc-r\">MALWARE C2</td></tr>\n          <tr><td><code>de9f102c...</code></td><td>Golang net/http</td><td class=\"tc-y\">REVIEW</td></tr>\n          <tr><td><code>cd08e31b...</code></td><td>curl (Linux)</td><td class=\"tc-g\">BENIGN</td></tr>\n          <tr><td><code>d801af15...</code></td><td>Chrome 120 (Win)</td><td class=\"tc-g\">BENIGN</td></tr>\n          <tr><td><code>a689bcd8...</code></td><td>Python Requests</td><td class=\"tc-y\">REVIEW</td></tr>\n        </table>\n        <div class=\"cb\" style=\"margin-top:10px;--cb-accent:var(--sonar2)\">\n<span class=\"C\"># Zeek: extract JA3 + SNI from ssl.log</span>\n<span class=\"K\">cat</span> ssl.log | <span class=\"K\">zeek-cut</span> \\\n    server_name ja3 ja3s validation_status \\\n    | <span class=\"K\">sort -u</span>\n\n<span class=\"C\"># Hunt for known-bad JA3:</span>\n<span class=\"K\">cat</span> ssl.log | <span class=\"K\">zeek-cut</span> ja3 \\\n    | <span class=\"K\">grep</span> \"72a7c4f777d392aa0a9b06b6d20dc79f\"\n<span class=\"C\"># Hit = Cobalt Strike default config (unmodified)</span>\n\n<span class=\"C\"># tshark: extract JA3 from live/PCAP</span>\n<span class=\"K\">tshark</span> -r cap.pcap \\\n    -Y \"tls.handshake.type==1\" \\\n    -T fields \\\n    -e ip.src -e ip.dst \\\n    -e tls.handshake.extensions_server_name</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- TLS cert forensics -->\n  <div class=\"g2\">\n    <div class=\"card cs\">\n      <div class=\"clabel\">Certificate Analysis</div>\n      <div class=\"ctitle sonar\">TLS CERTIFICATE RED FLAGS</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--sonar2)\">\n<span class=\"C\"># Extract certificate details with Zeek x509.log</span>\n<span class=\"K\">cat</span> x509.log | <span class=\"K\">zeek-cut</span> \\\n    certificate.subject certificate.issuer \\\n    certificate.not_valid_before certificate.not_valid_after \\\n    san.dns\n\n<span class=\"C\"># Red flags in certificate analysis:</span>\n<span class=\"R\">Self-signed:</span>\n  certificate.subject == certificate.issuer\n\n<span class=\"R\">Very short validity:</span>\n  not_valid_after - not_valid_before < 30 days\n\n<span class=\"R\">Generic subject fields:</span>\n  C=XX, O=Internet Widgits Pty Ltd (OpenSSL default)\n\n<span class=\"R\">Suspicious CN:</span>\n  CN matches IP address (e.g., CN=185.220.101.34)\n\n<span class=\"R\">Just-registered domain in SAN:</span>\n  compare first-seen in passive DNS vs cert issue date\n\n<span class=\"C\"># Extract cert from PCAP and inspect with openssl:</span>\n<span class=\"K\">tshark</span> -r cap.pcap \\\n    -Y \"tls.handshake.certificate\" \\\n    --export-objects tls,./certs/\n<span class=\"K\">openssl</span> x509 -in certs/cert.pem \\\n    -text -noout | <span class=\"K\">grep</span> -A5 \"Validity\\|Subject\\|Issuer\"</div>\n    </div>\n    <div class=\"card cs\">\n      <div class=\"clabel\">JA3S — Server Fingerprint</div>\n      <div class=\"ctitle sonar\">SERVER-SIDE TLS FINGERPRINTING</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">JA3S fingerprints the ServerHello — the server's TLS response. When combined with JA3 (client), it creates a client+server pair that uniquely identifies the malware-to-C2-server relationship.</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--sonar2)\">\n<span class=\"C\"># JA3S = MD5(TLSVersion,CipherSuite,Extensions)</span>\n<span class=\"C\"># From the ServerHello (server's response to ClientHello)</span>\n\n<span class=\"C\"># Known JA3/JA3S pairs:</span>\n<span class=\"H\">JA3  + JA3S → Tool identified</span>\n\n<span class=\"G\">Cobalt Strike C2:</span>\n  JA3:  72a7c4f777d392aa0a9b06b6d20dc79f\n  JA3S: 1aa7bf8b203f935be65c1b17534a7838\n  <span class=\"C\"># Both values match → high confidence Cobalt Strike</span>\n\n<span class=\"G\">Hunting in Zeek:</span>\n<span class=\"K\">cat</span> ssl.log | <span class=\"K\">zeek-cut</span> \\\n    orig_h resp_h server_name ja3 ja3s \\\n    | <span class=\"K\">awk</span> <span class=\"S\">'$4 != \"-\" && $5 != \"-\"'</span> \\\n    | <span class=\"K\">grep</span> -f known_bad_ja3.txt\n\n<span class=\"C\"># Lookup JA3 hashes:</span>\n<span class=\"C\"># https://ja3er.com/search/{ja3_hash}</span>\n<span class=\"C\"># https://sslbl.abuse.ch/ja3-fingerprints/</span>\n<span class=\"C\"># Zeek JA3 package: zkg install ja3</span></div>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════ C2 DETECTION ══════════════ -->\n<div class=\"module z1\" id=\"mod-c2\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">06</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Command & Control //</div>\n      <div class=\"sh-title\">C2 <span class=\"hl\">Beacon Detection</span></div>\n      <div class=\"sh-desc\">Statistical and behavioral methods for detecting C2 beaconing in network traffic — the attacker's most persistent network footprint. Periodicity analysis, byte volume patterns, and protocol anomalies.</div>\n    </div>\n  </div>\n\n  <div class=\"g2\" style=\"margin-bottom:14px\">\n    <div class=\"card cp\">\n      <div class=\"clabel\">Statistical Beacon Detection</div>\n      <div class=\"ctitle ping\">PERIODICITY ANALYSIS — PYTHON</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--ping2)\">\n<span class=\"tag\">PYTHON</span>\n<span class=\"K\">import</span> pandas <span class=\"K\">as</span> pd\n<span class=\"K\">import</span> numpy  <span class=\"K\">as</span> np\n<span class=\"K\">from</span> scipy.stats <span class=\"K\">import</span> variation\n\n<span class=\"K\">def</span> <span class=\"F\">detect_beacons</span>(\n    conn_log: str,\n    min_connections: int = <span class=\"N\">10</span>,\n    max_cv: float = <span class=\"N\">0.3</span>,          <span class=\"C\"># coefficient of variation threshold</span>\n    exclude_private: bool = <span class=\"G\">True</span>,\n) -> pd.DataFrame:\n    <span class=\"S\">\"\"\"\n    Analyze Zeek conn.log for beaconing behavior.\n    Low CV (coefficient of variation) = regular intervals = beacon.\n    \"\"\"</span>\n    df = pd.read_csv(conn_log, sep=<span class=\"S\">'\\t'</span>,\n                     comment=<span class=\"S\">'#'</span>, low_memory=<span class=\"G\">False</span>,\n                     names=[<span class=\"S\">'ts'</span>,<span class=\"S\">'uid'</span>,<span class=\"S\">'orig_h'</span>,<span class=\"S\">'orig_p'</span>,\n                            <span class=\"S\">'resp_h'</span>,<span class=\"S\">'resp_p'</span>,<span class=\"S\">'proto'</span>,\n                            <span class=\"S\">'service'</span>,<span class=\"S\">'duration'</span>,<span class=\"S\">'orig_bytes'</span>,\n                            <span class=\"S\">'resp_bytes'</span>,<span class=\"S\">'conn_state'</span>])\n    df[<span class=\"S\">'ts'</span>] = pd.to_numeric(df[<span class=\"S\">'ts'</span>], errors=<span class=\"S\">'coerce'</span>)\n    df = df.dropna(subset=[<span class=\"S\">'ts'</span>])\n\n    <span class=\"K\">if</span> exclude_private:\n        private = r<span class=\"S\">'^(10\\.|192\\.168\\.|172\\.(1[6-9]|2\\d|3[01])\\.|127\\.)'</span>\n        df = df[~df[<span class=\"S\">'resp_h'</span>].str.match(private, na=<span class=\"G\">False</span>)]\n\n    results = []\n    grouped = df.groupby([<span class=\"S\">'orig_h'</span>, <span class=\"S\">'resp_h'</span>, <span class=\"S\">'resp_p'</span>])\n\n    <span class=\"K\">for</span> (src, dst, dport), grp <span class=\"K\">in</span> grouped:\n        <span class=\"K\">if</span> len(grp) < min_connections: <span class=\"K\">continue</span>\n        times  = grp[<span class=\"S\">'ts'</span>].sort_values().values\n        deltas = np.diff(times)\n        <span class=\"K\">if</span> len(deltas) < <span class=\"N\">3</span>: <span class=\"K\">continue</span>\n\n        cv    = variation(deltas)  <span class=\"C\"># stddev/mean — lower = more regular</span>\n        mean  = np.mean(deltas)\n        total_bytes = grp[<span class=\"S\">'orig_bytes'</span>].sum() + grp[<span class=\"S\">'resp_bytes'</span>].sum()\n\n        <span class=\"K\">if</span> cv < max_cv:\n            results.append({\n                <span class=\"S\">'src'</span>:      src, <span class=\"S\">'dst'</span>: dst, <span class=\"S\">'port'</span>: dport,\n                <span class=\"S\">'count'</span>:    len(grp),\n                <span class=\"S\">'interval'</span>: round(mean, <span class=\"N\">1</span>),\n                <span class=\"S\">'cv'</span>:       round(cv, <span class=\"N\">4</span>),\n                <span class=\"S\">'bytes'</span>:    int(total_bytes),\n            })\n\n    out = pd.DataFrame(results)\n    <span class=\"K\">if</span> len(out) == <span class=\"N\">0</span>: <span class=\"K\">return</span> out\n    <span class=\"K\">return</span> out.sort_values(<span class=\"S\">'cv'</span>)  <span class=\"C\"># most regular first</span>\n\nbeacons = detect_beacons(<span class=\"S\">\"conn.log\"</span>)\n<span class=\"F\">print</span>(beacons.to_string(index=<span class=\"G\">False</span>))</div>\n    </div>\n\n    <div class=\"card cp\">\n      <div class=\"clabel\">Byte Volume Analysis</div>\n      <div class=\"ctitle ping\">C2 TRAFFIC VOLUME PATTERNS</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">C2 beacons have characteristic byte volume ratios. Small regular requests (commands) with occasional large responses (payload delivery) or large requests (exfil) are strong indicators.</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--ping2)\">\n<span class=\"C\"># Conn.log analysis: request/response byte ratio</span>\n<span class=\"K\">cat</span> conn.log | <span class=\"K\">zeek-cut</span> \\\n    orig_h resp_h resp_p orig_bytes resp_bytes service \\\n    | <span class=\"K\">awk</span> <span class=\"S\">'\n{\n  # C2 beacon pattern: small request, small response\n  # (no data — just keep-alive / status check)\n  if ($4+$5 < 2000 && $4 > 0 && $5 > 0) {\n    small[$1\"→\"$2\":\"$3]++\n  }\n  # Data exfil: large outbound, small inbound\n  if ($4 > 100000 && $5 < 1000) {\n    exfil[$1\"→\"$2\":\"$3] += $4\n  }\n}\nEND {\n  print \"=== SMALL BIDIRECTIONAL (potential beacon) ===\"\n  for(k in small) if(small[k]>10) print small[k], k\n  print \"=== LARGE OUTBOUND (potential exfil) ===\"\n  for(k in exfil) print exfil[k], k\n}'</span>\n\n<span class=\"C\"># Detect protocol mismatches (C2 hiding in DNS port)</span>\n<span class=\"K\">cat</span> conn.log | <span class=\"K\">zeek-cut</span> resp_p service \\\n    | <span class=\"K\">awk</span> <span class=\"S\">'$1==53 && $2!=\"dns\" && $2!=\"-\"'</span>\n<span class=\"C\"># Non-DNS traffic on port 53 = DNS port tunneling</span>\n\n<span class=\"C\"># Detect HTTPS on non-standard ports</span>\n<span class=\"K\">cat</span> conn.log | <span class=\"K\">zeek-cut</span> resp_p service \\\n    | <span class=\"K\">awk</span> <span class=\"S\">'$2==\"ssl\" && $1!=443 && $1!=8443 && $1!=465 && $1!=993'</span>\n<span class=\"C\"># TLS on weird port = C2 evasion attempt</span></div>\n    </div>\n  </div>\n\n  <div class=\"card\">\n    <div class=\"clabel\">C2 Framework Signatures</div>\n    <div class=\"ctitle\">KNOWN C2 NETWORK SIGNATURES</div>\n    <table class=\"dtable\">\n      <tr><th>C2 FRAMEWORK</th><th>NETWORK INDICATORS</th><th>DETECTION METHOD</th></tr>\n      <tr>\n        <td><strong>Cobalt Strike</strong></td>\n        <td>Default: <code>jquery-3.3.1.min.js</code> URI, cookie-based C2 data, checksum8 URI, specific malleable C2 headers. Default JA3: <code>72a7c4f7...</code></td>\n        <td class=\"tc-r\">JA3 match + URI pattern + Suricata ET rules</td>\n      </tr>\n      <tr>\n        <td><strong>Sliver</strong></td>\n        <td>mTLS default port 8888, WireGuard on 51820, HTTP/S with random URI paths, cert uses random org names</td>\n        <td class=\"tc-y\">Port 8888 + mTLS + cert org pattern</td>\n      </tr>\n      <tr>\n        <td><strong>Metasploit Meterpreter</strong></td>\n        <td>HTTPS on 4444/8443/443, specific TLS fingerprint, reverse_http URIs: <code>/V6XJP3_</code> type pattern</td>\n        <td class=\"tc-r\">JA3 + port + URI randomness</td>\n      </tr>\n      <tr>\n        <td><strong>Havoc Framework</strong></td>\n        <td>Default port 40056/443, AES-256 encrypted HTTP body, specific HTTP headers: <code>X-Havoc-*</code></td>\n        <td class=\"tc-y\">Custom HTTP header pattern</td>\n      </tr>\n      <tr>\n        <td><strong>Empire / PowerShell</strong></td>\n        <td>Regular HTTP polling, session cookies, default staging URI <code>/index.asp</code>, specific User-Agent</td>\n        <td class=\"tc-r\">URI + UA + interval analysis</td>\n      </tr>\n      <tr>\n        <td><strong>DNS C2 (dnscat2)</strong></td>\n        <td>Repeated TXT queries to single domain, hex-encoded subdomains, session IDs in labels</td>\n        <td class=\"tc-r\">DNS TXT + volume + label analysis</td>\n      </tr>\n    </table>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════ LATERAL MOVEMENT ══════════════ -->\n<div class=\"module z1\" id=\"mod-lateral\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">07</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Network-Level Attack Detection //</div>\n      <div class=\"sh-title\">Lateral Movement <span class=\"hl\">From Network Evidence</span></div>\n      <div class=\"sh-desc\">Lateral movement leaves distinctive network patterns — new SMB relationships, unusual Kerberos ticket requests, RDP from unexpected sources, and credential reuse across hosts.</div>\n    </div>\n  </div>\n\n  <div class=\"g2\" style=\"margin-bottom:14px\">\n    <div class=\"card cw\">\n      <div class=\"clabel\">SMB Lateral Movement</div>\n      <div class=\"ctitle warn\">DETECTING PsExec / SMB LATERAL MOVEMENT</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">SMB-based lateral movement (PsExec, WMI, Admin$) is highly visible in network captures. Key indicators: workstation-to-workstation SMB, ADMIN$ share access, and PSEXESVC service creation.</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--warn)\">\n<span class=\"tag\">ZEEK + BASH</span>\n<span class=\"C\"># Workstation-to-workstation SMB (unusual — should only go to servers)</span>\n<span class=\"C\"># Assumes workstations are in 10.1.x.x, servers in 10.2.x.x</span>\n<span class=\"K\">cat</span> conn.log | <span class=\"K\">zeek-cut</span> orig_h resp_h resp_p \\\n    | <span class=\"K\">awk</span> <span class=\"S\">'\n$3 == 445 &&\n/^10\\.1\\./ &&\n$2 ~ /^10\\.1\\./ {\n    print $1, \"→\", $2, \":445 (workstation-to-workstation SMB)\"\n}'</span>\n\n<span class=\"C\"># PsExec: ADMIN$ share access followed by service creation</span>\n<span class=\"C\"># Look in smb_mapping.log for ADMIN$ access:</span>\n<span class=\"K\">cat</span> smb_mapping.log | <span class=\"K\">zeek-cut</span> ts path \\\n    | <span class=\"K\">grep</span> \"ADMIN\\$\\|IPC\\$\\|C\\$\"\n\n<span class=\"C\"># SMB file writes to system paths (lateral tool staging)</span>\n<span class=\"K\">cat</span> smb_files.log | <span class=\"K\">zeek-cut</span> action path name \\\n    | <span class=\"K\">awk</span> <span class=\"S\">'$1==\"SMB::FILE_WRITE\"'</span> \\\n    | <span class=\"K\">grep</span> -i \"\\.exe\\|\\.dll\\|\\.ps1\\|\\.bat\"\n\n<span class=\"C\"># Suricata rule for PsExec ADMIN$ access:</span>\n<span class=\"C\">alert smb $HOME_NET any -> $HOME_NET 445 (</span>\n<span class=\"C\">    msg:\"PsExec ADMIN$ Share Access\";  </span>\n<span class=\"C\">    content:\"|00 00 00 00 0e 00 00 00|\"; depth:8; offset:4;</span>\n<span class=\"C\">    content:\"ADMIN$\"; nocase;</span>\n<span class=\"C\">    sid:9000010; rev:1;</span>\n<span class=\"C\">    classtype:policy-violation;</span>\n<span class=\"C\">)</span></div>\n    </div>\n\n    <div class=\"card cw\">\n      <div class=\"clabel\">Kerberos Forensics</div>\n      <div class=\"ctitle warn\">KERBEROASTING & PASS-THE-TICKET</div>\n      <div class=\"cbody\" style=\"margin-bottom:10px\">Kerberos attacks leave distinctive traffic patterns. AS-REP roasting, Kerberoasting, and Pass-the-Ticket all have network-level signatures.</div>\n      <div class=\"cb\" style=\"--cb-accent:var(--warn)\">\n<span class=\"tag\">TSHARK + ZEEK</span>\n<span class=\"C\"># AS-REP Roasting: TGT requests without pre-auth</span>\n<span class=\"C\"># (DONT_REQUIRE_PREAUTH set — hash returned without creds)</span>\n<span class=\"K\">tshark</span> -r cap.pcap -Y \\\n    \"kerberos.msg_type==10 && kerberos.PA_DATA_type!=2\" \\\n    -T fields -e ip.src -e kerberos.name_string\n\n<span class=\"C\"># Kerberoasting: many TGS requests in burst</span>\n<span class=\"C\"># (requesting service tickets for multiple SPNs)</span>\n<span class=\"K\">tshark</span> -r cap.pcap -Y \"kerberos.msg_type==12\" \\\n    -T fields -e ip.src -e kerberos.sname_string \\\n    | <span class=\"K\">sort | uniq -c | sort -rn</span>\n<span class=\"C\"># More than 5-10 TGS requests quickly = Kerberoasting</span>\n\n<span class=\"C\"># Zeek kerberos.log analysis:</span>\n<span class=\"K\">cat</span> kerberos.log | <span class=\"K\">zeek-cut</span> \\\n    client service success \\\n    | <span class=\"K\">awk</span> '$3==\"false\"' \\\n    | <span class=\"K\">sort | uniq -c | sort -rn</span>\n<span class=\"C\"># Failed Kerberos = wrong creds or ticket reuse</span>\n\n<span class=\"C\"># Golden/Silver ticket: unusual forged TGT properties</span>\n<span class=\"C\"># Ticket lifetime field = 10 years (default golden ticket)</span>\n<span class=\"K\">tshark</span> -r cap.pcap -Y \"kerberos.msg_type==11\" \\\n    -T fields -e kerberos.till \\\n    | <span class=\"K\">awk</span> -F'T' '$1 > \"2035\"'  <span class=\"C\"># ticket valid until 2035+ = forged</span></div>\n    </div>\n  </div>\n\n  <div class=\"card\" style=\"margin-bottom:14px\">\n    <div class=\"clabel\">Network Topology Mapping</div>\n    <div class=\"ctitle\">RECONSTRUCT ATTACKER MOVEMENT FROM CONN.LOG</div>\n    <div class=\"cb\">\n<span class=\"tag\">PYTHON</span>\n<span class=\"K\">import</span> pandas <span class=\"K\">as</span> pd\n<span class=\"K\">import</span> networkx <span class=\"K\">as</span> nx\n\n<span class=\"K\">def</span> <span class=\"F\">map_lateral_movement</span>(conn_log: str, suspicious_ports=(445,135,3389,5985,22)):\n    <span class=\"S\">\"\"\"Build lateral movement graph from conn.log.\"\"\"</span>\n    df = pd.read_csv(conn_log, sep=<span class=\"S\">'\\t'</span>, comment=<span class=\"S\">'#'</span>,\n                     usecols=[<span class=\"S\">'ts'</span>,<span class=\"S\">'orig_h'</span>,<span class=\"S\">'resp_h'</span>,<span class=\"S\">'resp_p'</span>,\n                               <span class=\"S\">'orig_bytes'</span>,<span class=\"S\">'resp_bytes'</span>],\n                     names=[<span class=\"S\">'ts'</span>,<span class=\"S\">'uid'</span>,<span class=\"S\">'orig_h'</span>,<span class=\"S\">'orig_p'</span>,<span class=\"S\">'resp_h'</span>,<span class=\"S\">'resp_p'</span>,\n                            <span class=\"S\">'proto'</span>,<span class=\"S\">'service'</span>,<span class=\"S\">'duration'</span>,<span class=\"S\">'orig_bytes'</span>,<span class=\"S\">'resp_bytes'</span>],\n                     low_memory=<span class=\"G\">False</span>)\n\n    <span class=\"C\"># Filter to lateral movement ports only</span>\n    lateral = df[df[<span class=\"S\">'resp_p'</span>].isin(suspicious_ports)]\n\n    <span class=\"C\"># Build directed graph</span>\n    G = nx.DiGraph()\n    <span class=\"K\">for</span> _, row <span class=\"K\">in</span> lateral.iterrows():\n        G.add_edge(row[<span class=\"S\">'orig_h'</span>], row[<span class=\"S\">'resp_h'</span>],\n                   port=row[<span class=\"S\">'resp_p'</span>],\n                   bytes=row[<span class=\"S\">'orig_bytes'</span>]+row[<span class=\"S\">'resp_bytes'</span>])\n\n    <span class=\"C\"># Find pivot points (hosts that connect AND receive connections)</span>\n    pivots = [n <span class=\"K\">for</span> n <span class=\"K\">in</span> G.nodes()\n              <span class=\"K\">if</span> G.in_degree(n) > <span class=\"N\">0</span> <span class=\"K\">and</span> G.out_degree(n) > <span class=\"N\">0</span>]\n\n    <span class=\"F\">print</span>(f<span class=\"S\">\"Hosts with lateral connections: {G.number_of_nodes()}\"</span>)\n    <span class=\"F\">print</span>(f<span class=\"S\">\"Lateral connections: {G.number_of_edges()}\"</span>)\n    <span class=\"F\">print</span>(f<span class=\"S\">\"\\nPivot points (attacker likely used these):\"</span>)\n    <span class=\"K\">for</span> p <span class=\"K\">in</span> pivots:\n        ins  = list(G.predecessors(p))\n        outs = list(G.successors(p))\n        <span class=\"F\">print</span>(f<span class=\"S\">\"  {p}: received from {ins} → moved to {outs}\"</span>)\n\n    <span class=\"K\">return</span> G\n\nG = map_lateral_movement(<span class=\"S\">\"conn.log\"</span>)\n<span class=\"C\"># Visualize: nx.draw(G, with_labels=True) + matplotlib</span></div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════ QUIZ ══════════════ -->\n<div class=\"module z1\" id=\"mod-quiz\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">∞</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-eyebrow\">// Module 07 Assessment //</div>\n      <div class=\"sh-title\">Network Forensics <span class=\"hl\">Exam</span></div>\n      <div class=\"sh-desc\">Ten questions covering PCAP analysis, Zeek log correlation, Suricata rules, DNS forensics, TLS/JA3 fingerprinting, C2 beacon detection, and lateral movement identification.</div>\n    </div>\n  </div>\n\n  <div id=\"quiz-container\"></div>\n\n  <div class=\"score-panel\">\n    <div class=\"score-big\" id=\"score-big\">—</div>\n    <div class=\"score-sub\" id=\"score-sub\">ANSWER QUESTIONS TO TRACK SCORE</div>\n    <div class=\"score-bar\"><div class=\"score-fill\" id=\"score-fill\" style=\"width:0%\"></div></div>\n    <button class=\"reset-btn\" onclick=\"resetQuiz()\">RESET EXAM</button>\n  </div>\n\n</div>\n</div>\n\n<script>\nfunction sw(id,btn){\n  document.querySelectorAll('.module').forEach(m=>m.classList.remove('active'));\n  document.querySelectorAll('.ntab').forEach(t=>t.classList.remove('active'));\n  document.getElementById('mod-'+id).classList.add('active');\n  btn.classList.add('active');\n  window.scrollTo({top:0,behavior:'smooth'});\n}\nfunction iTab(id,btn){\n  const mod=btn.closest('.module');\n  mod.querySelectorAll('.itab').forEach(t=>t.classList.remove('active'));\n  mod.querySelectorAll('.ipanel').forEach(p=>p.classList.remove('active'));\n  btn.classList.add('active');\n  document.getElementById('ip-'+id).classList.add('active');\n}\n\nconst Qs=[\n  {\n    q:\"Zeek's ssl.log shows a connection where ja3='72a7c4f777d392aa0a9b06b6d20dc79f' and server_name is empty (no SNI). What does this combination strongly indicate, and what is your immediate response?\",\n    opts:[\n      \"Normal browser traffic — Chrome sometimes omits SNI on internal connections\",\n      \"This JA3 is the default Cobalt Strike beacon signature. No SNI means the beacon is connecting to an IP directly (no domain), bypassing certificate validation. Immediately: (1) identify the source host, (2) correlate src IP with endpoint logs, (3) check conn.log for regularity/beaconing pattern, (4) block the destination at perimeter and isolate the source host\",\n      \"The JA3 indicates an outdated TLS 1.0 client — update the host's TLS configuration\",\n      \"Missing SNI is a Zeek parsing bug — re-run Zeek with a newer version\"\n    ],\n    correct:1,\n    explain:\"<strong>JA3 72a7c4f7... is the well-known default Cobalt Strike beacon fingerprint.</strong> The absence of SNI confirms the beacon is connecting directly to an IP address (not a domain name), which means the C2 operator either used a raw IP or the beacon is doing direct IP beaconing — common in Cobalt Strike's default HTTPS listener before malleable C2 profiles are applied. The combination: known-bad JA3 + no SNI + regular intervals in conn.log = high-confidence Cobalt Strike. Note: sophisticated operators change the JA3 via malleable C2 profiles, so absence of this hash doesn't rule out CS — but its presence is definitive.\"\n  },\n  {\n    q:\"You're analyzing a Zeek dns.log and find host 10.1.5.23 has made 847 NXDOMAIN queries in one hour to random-looking domains like 'k3mq9xzt4.com', 'n8vb2cjhm6.net'. A Python entropy calculation shows these domains have entropy > 3.8 and consonant ratios > 0.78. What Wireshark display filter would you use to capture the full DNS traffic from this host for deeper analysis?\",\n    opts:[\n      \"ip.addr == 10.1.5.23 && dns\",\n      \"ip.src == 10.1.5.23 && dns && dns.flags.rcode == 3\",\n      \"Both are useful: 'ip.addr == 10.1.5.23 && dns' for full bidirectional DNS picture; add '&& dns.flags.rcode == 3' to isolate NXDOMAIN responses. Also use 'dns.qry.name.len > 20' to find the high-entropy labels specifically\",\n      \"dns.qry.name contains 'com' — find all .com queries from the host\"\n    ],\n    correct:2,\n    explain:\"<strong>Layered filtering gives the most complete picture.</strong> Start broad: <code>ip.addr == 10.1.5.23 && dns</code> — this shows all DNS traffic (queries AND responses) both from and to the host. Then narrow: add <code>&& dns.flags.rcode == 3</code> to isolate NXDOMAIN responses — this shows which DGA domains aren't resolving (all of them, for a bot that hasn't hit the registered C2 domain yet). The label length filter <code>dns.qry.name.len > 20</code> helps isolate the DGA-style queries from legitimate short-label queries. Filtering only on src limits you to queries; src OR dst (addr) gives the full conversation. Layer these filters progressively rather than jumping to a narrow filter that might miss context.\"\n  },\n  {\n    q:\"In a Suricata rule you write: 'threshold:type limit, track by_src, count 1, seconds 60'. An analyst asks why not use 'count 1, seconds 1' to catch every single occurrence. What is the correct explanation?\",\n    opts:[\n      \"'seconds 1' is invalid syntax — minimum is 60 seconds\",\n      \"Using count 1, seconds 1 would generate one alert per packet per second, causing alert storms that overwhelm the SIEM and train analysts to ignore the rule. 'count 1, seconds 60' means: alert at most once per source IP per 60 seconds — maintaining signal while suppressing duplicate alerts for sustained activity\",\n      \"The threshold keyword requires count to equal the seconds value — they must match\",\n      \"'by_src' tracking only works with counts above 5 — use by_dst for single-count thresholds\"\n    ],\n    correct:1,\n    explain:\"<strong>Threshold tuning prevents alert storms and analyst fatigue.</strong> Without thresholds, a single infected host making 1000 C2 connections/hour would generate 1000 identical alerts — analysts quickly learn to ignore that rule. The 'limit' type means: fire the alert once, then suppress additional alerts from the same src for the window. 'both' type means: fire once AFTER count is reached, then suppress. For high-frequency C2 beacons, 'type both, count 5, seconds 60' is often better than 'limit, count 1' — it requires seeing at least 5 occurrences before alerting (reduces FPs) but still only fires once per minute. Tuning thresholds is as important as the detection logic itself.\"\n  },\n  {\n    q:\"Zeek's conn.log shows host 10.1.3.44 connecting to 185.220.101.34:443 with interval mean=62.3s and coefficient of variation=0.04. The origin bytes average 347 bytes per connection and response bytes average 284. What does this traffic profile tell you and what is missing from this analysis?\",\n    opts:[\n      \"This is normal HTTPS keep-alive traffic — proceed to the next alert\",\n      \"CV=0.04 is extremely regular (near-zero variation) and the 62s interval matches a C2 beacon with ~3% jitter. Small bidirectional byte counts (347/284) match a minimal beacon with no large payload delivery yet. Missing: JA3 fingerprint (check ssl.log for the ja3 field), DNS resolution history for 185.220.101.34 (passive DNS), and endpoint process correlation (which process on 10.1.3.44 owns this connection?)\",\n      \"The CV of 0.04 indicates this is compressed video traffic — the regularity is from the video codec's frame rate\",\n      \"Response bytes should be larger than request bytes for C2 — this pattern doesn't match because response bytes (284) are less than origin bytes (347)\"\n    ],\n    correct:1,\n    explain:\"<strong>Complete beacon profile with identified analytical gaps.</strong> CV=0.04 (4% variation in intervals) is the mathematical signature of automated periodic communication — humans don't communicate this regularly. 62s mean interval is consistent with a common C2 sleep configuration. The byte volumes (347 origin / 284 response) are classic minimal beacon: small HTTP POST (command check-in) with small HTTP 200 response (no pending commands). What's missing for a complete picture: (1) ssl.log → ja3 field: does the TLS fingerprint match a known C2 framework? (2) dns.log: did the host resolve 185.220.101.34 to a domain? What domain? When? (3) Endpoint correlation: EDR/Sysmon data — which process (pid) owns the connection on 10.1.3.44?\"\n  },\n  {\n    q:\"DNS tunneling is detected in a PCAP. The suspected host is making TXT queries to 'aXBjb25maWc=.tunnel.evil-domain.com'. Decoding 'aXBjb25maWc=' from base64 gives 'ipconfig'. What forensic conclusions can you draw and what additional analysis is needed?\",\n    opts:[\n      \"The host ran 'ipconfig' locally — this is not malware, just a sysadmin checking network config\",\n      \"The base64-decoded 'ipconfig' in the DNS TXT query label confirms active DNS C2 tunneling: the attacker is sending Windows commands encoded in DNS subdomain labels. The response TXT records contain the command output. Additional analysis: (1) decode ALL query labels from this host, (2) decode all TXT response records, (3) reconstruct the complete attacker session from the query/response sequence, (4) identify what other commands were executed, (5) check conn.log for data volume to quantify what was exfiltrated\",\n      \"This is automatic Windows DNS telemetry — Microsoft encodes diagnostic data in DNS TXT records\",\n      \"The domain tunnel.evil-domain.com must be blocked at the DNS level — no further analysis needed\"\n    ],\n    correct:1,\n    explain:\"<strong>Confirmed DNS command-and-control channel with active command execution.</strong> The decoded content 'ipconfig' is a Windows reconnaissance command — this confirms bidirectional DNS tunneling: attacker sends commands in query labels (base64 encoded), responses (TXT records) contain the command output. The analysis steps: (1) Extract all labels from tunnel.evil-domain.com queries and decode each from base64 — reconstruct the full command history. (2) Extract all TXT record responses and decode — reconstruct the full output history. (3) Sequence queries+responses by timestamp to reconstruct the attacker's session timeline. (4) Check conn.log for total bytes to/from the DNS server and the resolver — quantify data transferred. (5) This constitutes an active incident — the attacker has shell-level access and is actively issuing commands.\"\n  },\n  {\n    q:\"A Zeek conn.log shows 10.1.2.15 (workstation) connecting to 10.1.8.44 (another workstation) on port 445, followed 8 minutes later by 10.1.8.44 connecting to 10.1.9.12 on port 445, then 10.1.9.12 connecting to 10.1.10.3 (DC) on port 445. What is the attack pattern and which log provides the most actionable detail?\",\n    opts:[\n      \"Normal Windows file sharing — workstations frequently access each other over SMB\",\n      \"This is a lateral movement chain via SMB: attacker pivoted from .15 → .44 → .12 → DC. The smb_files.log and smb_mapping.log provide the most actionable detail — they show exactly which shares were accessed (ADMIN$, C$, IPC$), which files were written (lateral tools like PsExec binary), and the SMB session metadata including the credentials used for each hop\",\n      \"This is Kerberos ticket relay — the SMB connections are just part of authentication\",\n      \"The DC connection is concerning but workstation-to-workstation is normal — only alert on the DC connection\"\n    ],\n    correct:1,\n    explain:\"<strong>Classic hop-chain lateral movement: workstation → workstation → DC.</strong> The pattern (WS1→WS2→WS3→DC on port 445, each 8 minutes apart) is a textbook pivot chain: attacker compromises WS1, uses credentials/hash to move to WS2, then WS3, targeting the Domain Controller. Zeek logs to consult: <code>smb_mapping.log</code> shows which shares were accessed (ADMIN$ = PsExec territory, C$ = direct file system access, IPC$ = RPC), <code>smb_files.log</code> shows what files were read/written (look for .exe drops — PsExec binary, custom backdoors), <code>ntlm.log</code> or <code>kerberos.log</code> shows authentication method (NTLM = possible Pass-the-Hash; Kerberos = possible Pass-the-Ticket or Kerberoasting precursor). The time gaps (8 min) suggest human operator, not automated — APT behavior.\"\n  },\n  {\n    q:\"You write a Suricata rule with 'flow:established,to_server' but an analyst reports the rule never fires on HTTP POST requests. The capture clearly shows matching POSTs. What is the likely cause?\",\n    opts:[\n      \"Suricata doesn't support HTTP detection — use Zeek instead\",\n      \"The alert keyword should be 'pass' for HTTP traffic — 'alert' only works for TCP\",\n      \"The rule may be missing the 'app-layer-protocol:http' keyword, OR the HTTP traffic is on a non-standard port that Suricata isn't decoding as HTTP. Suricata auto-detects HTTP only on ports in the http.ports variable (default: 80,8080,8888,...). If the C2 uses port 4444 for HTTP, add 'app-layer-protocol:http' to force protocol detection regardless of port\",\n      \"flow:established excludes HTTP because HTTP is stateless — use flow:stateless instead\"\n    ],\n    correct:2,\n    explain:\"<strong>Protocol detection port configuration and app-layer-protocol keyword.</strong> Suricata performs protocol detection based on configured port lists AND content inspection. By default, HTTP is only detected on ports in <code>app-layer.protocols.http.request-body-limit</code> and the <code>http.ports</code> variable. If C2 traffic uses HTTP on port 443 (with 'ssl' wrapping) or an unusual port like 4444, Suricata may not apply HTTP keywords. Fix: add <code>app-layer-protocol:http;</code> to force application layer detection. Also verify the rule's port specification — if you wrote 'any any -> any 443', TLS-wrapped HTTP may not expose the HTTP layer for content inspection. For HTTP over TLS, you need separate TLS-level detection or to decrypt the traffic first. Always test rules against a known-good PCAP before deploying.\"\n  },\n  {\n    q:\"A PCAP shows TXT record queries with labels like 'A1B2C3D4.data.tunnel.com', 'E5F6A7B8.data.tunnel.com' arriving at 200ms intervals. The labels are hex strings. The total query volume is 50KB in 10 minutes. What type of tunneling is this and how fast is the channel?\",\n    opts:[\n      \"This is DNSSEC validation traffic — DNSSEC uses hex labels for key material\",\n      \"This is a hex-encoded DNS exfiltration channel. 50KB in 10 minutes = ~83 bytes/second. Each hex label (8 chars) encodes 4 bytes. At 200ms intervals: ~5 queries/second × ~4 bytes = ~20 bytes/sec query data plus TXT response data. This is a slow but stealthy channel — suitable for credential/config exfil. The 200ms interval suggests automated operation (not human-typed commands)\",\n      \"This is legitimate certificate transparency log monitoring — hex labels are certificate hashes\",\n      \"At 50KB/10min this is too slow to be exfiltration — the threshold for concern is 1MB minimum\"\n    ],\n    correct:1,\n    explain:\"<strong>Hex-encoded DNS data exfiltration channel — speed calculation matters.</strong> The channel analysis: 8-char hex labels = 4 bytes of data each. At 200ms intervals = 5 queries/second × 4 bytes = 20 bytes/second of outbound data in queries. TXT responses can carry more (up to ~255 bytes each), so inbound C2 commands can arrive faster than outbound data. 50KB in 10 minutes = 83 bytes/second total — this suggests hex labels aren't the only data source OR responses carry significant data. Real-world implication: at 83 bytes/second, exfiltrating a 1MB credential file would take ~3.3 hours — slow but under normal DNS traffic thresholds. Detection: regular 200ms intervals are machine-generated (too precise for human interaction), hex labels have low entropy (0-9, A-F only), and the volume pattern (sustained low-rate) differs from legitimate bursty DNS usage.\"\n  },\n  {\n    q:\"Zeek generates a files.log entry with md5='d41d8cd98f00b204e9800998ecf8427e'. This is the MD5 of an empty file. The file has mime_type='application/zip' and total_bytes=0. What does this indicate during an investigation?\",\n    opts:[\n      \"A legitimate empty ZIP file was transferred — no concern\",\n      \"MD5 d41d8cd98f00b204e9800998ecf8427e is the universally known hash of a zero-byte file. A ZIP with application/zip MIME type but zero bytes and this hash indicates: either (1) the file transfer was aborted/connection dropped before data was sent, (2) the file was deliberately sent empty as a decoy or connectivity test, or (3) Zeek failed to capture the file payload. Cross-reference conn.log: if orig_bytes > 0 but files.log shows 0 bytes, data was transferred but Zeek failed to extract it — look at the raw PCAP\",\n      \"This hash means the file is guaranteed safe — known-good files have predictable MD5s\",\n      \"Zero-byte files cannot have a ZIP MIME type — this is a Zeek parsing error\"\n    ],\n    correct:1,\n    explain:\"<strong>d41d8cd98f00b204e9800998ecf8427e — the famous empty file MD5.</strong> This is one of the most recognizable hashes in digital forensics: it's the MD5 of an empty (0-byte) input. When you see this in files.log alongside a non-zero MIME type, it warrants investigation. The most forensically important scenario: if conn.log shows orig_bytes > 0 for the same uid (connection), but files.log shows total_bytes=0, data was transmitted but Zeek's file extraction failed — possibly due to encryption, unusual fragmentation, or stream reassembly issues. Check the raw PCAP with tshark --export-objects for that stream. The 'application/zip' MIME with 0 bytes could also mean the HTTP response sent a Content-Type header but the body transfer stalled — useful for reconstructing exactly what happened in the connection.\"\n  },\n  {\n    q:\"A network graph built from conn.log shows host 10.1.5.5 has an in-degree of 1 (received one connection, from the initial compromised host) and an out-degree of 12 (connected to 12 different internal hosts on ports 445, 3389, 22). What role does 10.1.5.5 play in the attack and what is your containment priority?\",\n    opts:[\n      \"10.1.5.5 is a network scanner — run vulnerability scans against it to find the patch gap\",\n      \"10.1.5.5 is the primary pivot host: it received the initial lateral movement from the entry point and then spread to 12 additional hosts. High out-degree with targeted ports (445=SMB, 3389=RDP, 22=SSH) confirms active attacker usage as a staging point. Containment priority: (1) isolate 10.1.5.5 immediately — it is actively spreading, (2) identify all 12 downstream hosts and assess their compromise status, (3) capture memory from 10.1.5.5 before isolation to preserve attacker tools, (4) do NOT reboot — memory evidence critical\",\n      \"10.1.5.5 is a jump server used by IT for legitimate administration — verify with the sysadmin before taking action\",\n      \"Out-degree of 12 is low — only isolate hosts with out-degree > 50\"\n    ],\n    correct:1,\n    explain:\"<strong>High out-degree pivot host = active attacker staging point — immediate priority.</strong> In a lateral movement graph: in-degree = how many hosts connected to this one (1 = came from the entry point), out-degree = how many hosts this one connected to (12 = active lateral spread). The specific ports (445/SMB, 3389/RDP, 22/SSH) confirm this is attacker lateral movement, not backup jobs or patch management. Correct response sequence: (1) Memory capture FIRST (winpmem/LiME) — the attacker's tools, credentials, and C2 config are in RAM. (2) Isolate 10.1.5.5 at the network level (firewall rule or EDR isolation — not power-off). (3) Enumerate all 12 downstream hosts — each is potentially compromised. (4) Check each downstream host's conn.log out-degree — did any of the 12 also spread further? Build the complete propagation tree before any remediation.\"\n  }\n];\n\nlet answered=new Array(Qs.length).fill(false);\nlet score=0;\nconst topics=['JA3 Fingerprinting','DNS Filtering','Suricata Thresholds','Beacon Profiling','DNS Tunneling','Lateral Movement SMB','Suricata Rules','DNS Exfil Speed','File Forensics','Graph Analysis'];\n\nfunction buildQuiz(){\n  const c=document.getElementById('quiz-container');\n  c.innerHTML='';\n  Qs.forEach((q,qi)=>{\n    const d=document.createElement('div');\n    d.className='qcard';\n    d.innerHTML=`\n      <div class=\"qnum\">Q${String(qi+1).padStart(2,'0')} / ${Qs.length} · ${topics[qi]}</div>\n      <div class=\"qtext\">${q.q}</div>\n      <div class=\"qopts\">${q.opts.map((o,oi)=>`<button class=\"qopt\" onclick=\"ans(${qi},${oi},this)\">${String.fromCharCode(65+oi)}. ${o}</button>`).join('')}</div>\n      <div class=\"qexplain\" id=\"exp-${qi}\">${q.explain}</div>\n    `;\n    c.appendChild(d);\n  });\n  updateScore();\n}\n\nfunction ans(qi,oi,btn){\n  if(answered[qi])return;\n  answered[qi]=true;\n  btn.closest('.qopts').querySelectorAll('.qopt').forEach(b=>b.classList.add('locked'));\n  if(oi===Qs[qi].correct){btn.classList.add('correct');score++;}\n  else{btn.classList.add('wrong');btn.closest('.qopts').querySelectorAll('.qopt')[Qs[qi].correct].classList.add('correct');}\n  document.getElementById('exp-'+qi).classList.add('show');\n  updateScore();\n}\n\nfunction updateScore(){\n  const done=answered.filter(Boolean).length;\n  const big=document.getElementById('score-big');\n  const sub=document.getElementById('score-sub');\n  const fill=document.getElementById('score-fill');\n  if(done===0){big.textContent='—';sub.textContent='ANSWER QUESTIONS TO TRACK SCORE';return;}\n  const pct=Math.round(score/done*100);\n  big.textContent=`${score}/${done}`;\n  const rem=Qs.length-done;\n  sub.textContent=rem>0?`${pct}% · ${rem} REMAINING`:pct>=80?`${pct}% · NETWORK ANALYST CERTIFIED`:pct>=60?`${pct}% · REVIEW WEAK AREAS`:`${pct}% · REPEAT MODULE`;\n  fill.style.width=pct+'%';\n  fill.style.background=pct>=80?'#00ffcc':pct>=60?'#ff8c1a':'#ff2244';\n}\n\nfunction resetQuiz(){\n  answered=new Array(Qs.length).fill(false);\n  score=0;\n  buildQuiz();\n}\n\nbuildQuiz();\n</script>\n</body>\n</html>\n";

export default networkForensicsHtml;
